// Section 5 & 6: Dataset Schema & Metadata Model

export enum DataCategory {
  BOUNDARIES = 'Boundaries',
  DEMOGRAPHICS = 'Demographics',
  ENVIRONMENT = 'Environment',
  ECONOMY = 'Economy',
  INFRASTRUCTURE = 'Infrastructure'
}

export enum IngestionStatus {
  PENDING = 'PENDING',
  PROCESSING = 'PROCESSING',
  COMPLETED = 'COMPLETED',
  FAILED = 'FAILED'
}

export enum ValidationStatus {
  VERIFIED = 'VERIFIED',
  WARNING = 'WARNING',
  ERROR = 'ERROR',
  UNCHECKED = 'UNCHECKED'
}

export interface ValidationReport {
  status: ValidationStatus;
  issues: string[];
  timestamp: string;
}

export interface TemporalLayer {
  year: string;
  path: string; // URL to GeoJSON for this specific year
}

// New: Centralized Styling Contract for Viewer/Catalog consistency
export interface DatasetStyle {
  color?: string;
  weight?: number;
  fillOpacity?: number;
  dashArray?: string;
}

export interface Dataset {
  id: string;
  title: string;
  description: string;
  category: DataCategory;
  lastUpdated: string;
  format: 'GeoJSON' | 'CSV' | 'Shapefile' | 'API';
  size: string;
  source: string; // e.g., "Bureau of Statistics"
  downloadUrl?: string;
  geojsonUrl?: string; // URL for map preview
  imageUrl: string;

  // Section 7: Pipeline Fields
  ingestionStatus?: IngestionStatus;
  validationReport?: ValidationReport;
  metadataHash?: string; // For integrity

  // Tier 3: Temporal Support
  temporalLayers?: TemporalLayer[];

  // New: Visual Configuration
  style?: DatasetStyle;
}

export interface AnalysisPost {
  id: string;
  title: string;
  excerpt: string;
  author: string;
  date: string;
  imageUrl: string;
  tags: string[];
}

// Section 9: Error States / Edge Cases
export interface AppError {
  code: string;
  message: string;
  severity: 'low' | 'medium' | 'critical';
  context?: Record<string, any>;
}

export type ViewState = 
  | 'HOME' 
  | 'CATALOG' 
  | 'MAP' 
  | 'DOCS' 
  | 'ANALYSIS' 
  | 'ABOUT' 
  | 'INTERNAL_LOG' 
  | 'CHANGELOG'
  | 'SUPPORT'
  | 'REPORT_ISSUE'
  // Blog Module Routes
  | 'BLOG_INDEX'
  | 'BLOG_POST'
  | 'BLOG_CATEGORY'
  | 'BLOG_ARCHIVE'
  | 'BLOG_SEARCH'
  // Admin Routes
  | 'ADMIN_ACCESS'
  | 'TRIAGE_PROMPT_LIBRARY';

// Section 8: Search Index Model
export interface SearchResult {
  item: Dataset;
  score: number;
  matches: string[];
}

