import React, { useState, useEffect, useRef } from 'react';
import { Dataset, SearchResult, DataCategory } from '../types';
import { DataPipeline } from '../services/dataPipeline';
import { SearchEngine } from '../services/searchEngine';
import { GLOBAL_GEOJSON_DB } from '../data/geoJsonData';
import { CatalogCard } from './CatalogCard';

declare global {
  interface Window {
    L: any;
  }
}

interface CatalogProps {
  onOpenMap?: (dataset: Dataset) => void;
}

export const Catalog: React.FC<CatalogProps> = ({ onOpenMap }) => {
  // Data State
  const [datasets, setDatasets] = useState<Dataset[]>([]);
  const [filteredResults, setFilteredResults] = useState<SearchResult[]>([]);
  const [loading, setLoading] = useState(true);

  // Filter State
  const [searchQuery, setSearchQuery] = useState('');
  const [activeCategory, setActiveCategory] = useState<DataCategory | 'ALL'>('ALL');

  // Selection & Detail State
  const [selectedDataset, setSelectedDataset] = useState<Dataset | null>(null);
  const [previewData, setPreviewData] = useState<any[] | null>(null);
  const [loadingPreview, setLoadingPreview] = useState(false);

  // Map State
  const [showMap, setShowMap] = useState(false);
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const mapInstanceRef = useRef<any>(null);

  // Initial Data Ingestion (Section 7)
  useEffect(() => {
    const loadData = async () => {
      setLoading(true);
      try {
        const data = await DataPipeline.ingestCatalog();
        setDatasets(data);
        // Initial filter
        if (data.length > 0) setSelectedDataset(data[0]);
      } catch (err) {
        console.error("Ingestion Pipeline Failed", err);
      } finally {
        setLoading(false);
      }
    };
    loadData();
  }, []);

  // Search & Filter Logic (Section 8)
  useEffect(() => {
    // 1. Full text search
    let results = SearchEngine.search(datasets, searchQuery);

    // 2. Category Filter
    if (activeCategory !== 'ALL') {
      results = results.filter(r => r.item.category === activeCategory);
    }

    setFilteredResults(results);
  }, [searchQuery, activeCategory, datasets]);

  // Extraction Logic on Selection
  useEffect(() => {
    // Reset map view on new selection
    setShowMap(false);

    if (selectedDataset) {
      const fetchPreview = async () => {
        setLoadingPreview(true);
        setPreviewData(null);
        try {
          const extracted = await DataPipeline.extractPreview(selectedDataset);
          setPreviewData(extracted);
        } catch (e) {
          console.error("Extraction Failed", e);
        } finally {
          setLoadingPreview(false);
        }
      };
      fetchPreview();
    }
  }, [selectedDataset]);

  // Leaflet Map Logic (Preview Only)
  useEffect(() => {
    if (!showMap || !selectedDataset || !selectedDataset.geojsonUrl || !mapContainerRef.current) return;

    // Initialize Map if needed
    if (!mapInstanceRef.current && window.L) {
      const L = window.L;
      mapInstanceRef.current = L.map(mapContainerRef.current, {
         attributionControl: false,
         zoomControl: false 
      }).setView([5.5, -58.8], 6);

      // Add Tile Layer (CartoDB Dark for consistency or adjust based on theme? Sticking to dark map for contrast)
      L.tileLayer('https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png', {
        maxZoom: 19
      }).addTo(mapInstanceRef.current);
    }

    const map = mapInstanceRef.current;

    // Clear existing layers
    map.eachLayer((layer: any) => {
      if (!layer._url) map.removeLayer(layer); // Remove only overlays, keep tile layer
    });

    // Load GeoJSON from Centralized DB
    const loadLayer = () => {
       const mockGeoJson = GLOBAL_GEOJSON_DB[selectedDataset.geojsonUrl!];
       if (mockGeoJson && window.L) {
         // Use centralized style from contract, or fallback
         const styleConfig = selectedDataset.style || {};
         const defaultStyle = { color: "#FFC20E", weight: 2, fillOpacity: 0.2 };

         const layer = window.L.geoJSON(mockGeoJson, {
            style: { ...defaultStyle, ...styleConfig }
         }).addTo(map);

         try {
            map.fitBounds(layer.getBounds(), { padding: [20, 20] });
         } catch(e) { /* ignore bounds error for empty features */ }
       }
    };
    loadLayer();

    // Force resize trigger for Leaflet
    setTimeout(() => { map.invalidateSize() }, 100);

  }, [showMap, selectedDataset]);

  return (
    <div className="min-h-screen bg-cream-100 dark:bg-black pt-4 pb-12 flex flex-col h-screen overflow-hidden transition-colors duration-300">
      {/* Header Bar */}
      <div className="px-6 pb-4 border-b border-cream-300 dark:border-nightBorder-600 bg-cream-100 dark:bg-black z-10 space-y-4">
        <div className="flex justify-between items-center">
          <div>
            <h2 className="text-2xl font-serif font-bold text-ink-900 dark:text-white tracking-tight">Data Catalog <span className="text-brand-green-600 dark:text-nightAccent-green">Terminal</span></h2>
            <div className="text-[10px] text-ink-500 dark:text-gray-500 font-mono mt-1">
              CONNECTED: GUYNODE_MAINNET • LATENCY: 24ms • INGESTION: ACTIVE
            </div>
          </div>
          <div className="flex gap-4">
            <input 
              type="text" 
              placeholder="> SEARCH DATASETS..." 
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="bg-cream-200 dark:bg-nightBg-800 border border-cream-300 dark:border-nightBorder-600 rounded-sm px-4 py-2 text-sm text-ink-900 dark:text-nightAccent-gold font-mono focus:border-brand-green-500 dark:focus:border-bloom-accent outline-none w-80 uppercase placeholder-ink-500 dark:placeholder-gray-600" 
            />
          </div>
        </div>

        {/* Category Chips */}
        <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide">
          <button 
            onClick={() => setActiveCategory('ALL')}
            className={`px-4 py-1 rounded-full text-xs font-bold border transition-colors ${activeCategory === 'ALL' ? 'bg-ink-900 text-cream-100 border-ink-900 dark:bg-white dark:text-black dark:border-white' : 'text-ink-500 border-cream-300 hover:border-ink-900 dark:text-gray-400 dark:border-white/20 dark:hover:border-white'}`}
          >
            ALL
          </button>
          {Object.values(DataCategory).map(cat => (
             <button 
              key={cat}
              onClick={() => setActiveCategory(cat)}
              className={`px-4 py-1 rounded-full text-xs font-bold border transition-colors whitespace-nowrap ${activeCategory === cat ? 'bg-brand-green-600 text-white border-brand-green-600 dark:bg-nightAccent-green dark:text-white dark:border-nightAccent-green' : 'text-ink-500 border-cream-300 hover:border-brand-green-600 dark:text-gray-400 dark:border-white/20 dark:hover:border-white'}`}
            >
              {cat}
            </button>
          ))}
        </div>
      </div>

      <div className="flex flex-1 overflow-hidden">

        {/* Left Pane: Dataset List */}
        <div className="w-1/3 border-r border-cream-300 dark:border-nightBorder-600 overflow-y-auto bg-cream-100 dark:bg-black custom-scrollbar transition-colors duration-300">
          {loading ? (
             <div className="p-8 text-center font-mono text-ink-500 dark:text-gray-500 animate-pulse">> INITIALIZING PIPELINE...</div>
          ) : (
            <div className="divide-y divide-cream-300 dark:divide-white/5">
              {filteredResults.map(({ item }) => (
                <CatalogCard 
                  key={item.id}
                  dataset={item}
                  isSelected={selectedDataset?.id === item.id}
                  onClick={() => setSelectedDataset(item)}
                />
              ))}
              {filteredResults.length === 0 && (
                <div className="p-8 text-center text-ink-500 dark:text-gray-600 text-sm">No datasets found matching query.</div>
              )}
            </div>
          )}
        </div>

        {/* Right Pane: Detail & Extraction View */}
        <div className="w-2/3 bg-cream-200 dark:bg-nightBg-800 flex flex-col overflow-hidden relative transition-colors duration-300">
          {/* Background Grid Pattern */}
          <div className="absolute inset-0 bg-[url('https://grainy-gradients.vercel.app/noise.svg')] opacity-5 pointer-events-none"></div>

          {selectedDataset ? (
            <div className="flex flex-col h-full overflow-y-auto custom-scrollbar">
              {/* Dataset Metadata Header */}
              <div className="p-6 border-b border-cream-300 dark:border-white/10 bg-cream-100/50 dark:bg-bloom-card/50">
                <div className="flex justify-between items-start mb-4">
                  <h1 className="text-2xl font-bold text-ink-900 dark:text-white max-w-2xl">{selectedDataset.title}</h1>
                  <div className="flex gap-2">
                    {/* Map Toggle Button */}
                    {selectedDataset.geojsonUrl ? (
                      <button 
                        onClick={() => setShowMap(!showMap)}
                        className={`text-xs font-bold px-4 py-2 rounded transition-colors uppercase tracking-widest border ${showMap ? 'bg-ink-900 text-white border-ink-900 dark:bg-white dark:text-black dark:border-white' : 'bg-transparent text-ink-900 border-ink-900/20 hover:border-ink-900 dark:text-white dark:border-white/20 dark:hover:border-white'}`}
                      >
                        {showMap ? 'Hide Preview' : 'Preview'}
                      </button>
                    ) : (
                      <button disabled className="text-xs font-bold px-4 py-2 rounded border border-cream-300 text-ink-500 dark:border-white/5 dark:text-gray-600 uppercase tracking-widest cursor-not-allowed">
                        No Map Preview
                      </button>
                    )}

                    {/* Open in Main Viewer */}
                     {selectedDataset.geojsonUrl && onOpenMap && (
                      <button 
                        onClick={() => onOpenMap(selectedDataset)}
                        className="bg-white/50 hover:bg-white text-ink-900 border border-cream-300 dark:bg-white/10 dark:hover:bg-white/20 dark:text-white dark:border-white/10 text-xs font-bold px-4 py-2 rounded transition-colors uppercase tracking-widest"
                      >
                        Open In GIS Viewer
                      </button>
                    )}

                    <button className="bg-brand-green-600 hover:bg-brand-green-500 dark:bg-nightAccent-blue dark:hover:bg-blue-600 text-white text-xs font-bold px-4 py-2 rounded transition-colors uppercase tracking-widest">
                      Download {selectedDataset.format}
                    </button>
                  </div>
                </div>

                <p className="text-ink-700 dark:text-gray-300 text-sm mb-6 max-w-3xl leading-relaxed">{selectedDataset.description}</p>

                <div className="grid grid-cols-4 gap-4 text-xs font-mono border-t border-cream-300 dark:border-white/5 pt-4">
                  <div>
                    <div className="text-ink-500 dark:text-gray-500 mb-1">SOURCE AUTHORITY</div>
                    <div className="text-brand-gold-600 dark:text-nightAccent-gold">{selectedDataset.source}</div>
                  </div>
                  <div>
                    <div className="text-ink-500 dark:text-gray-500 mb-1">LAST UPDATED</div>
                    <div className="text-ink-900 dark:text-white">{selectedDataset.lastUpdated}</div>
                  </div>
                  <div>
                    <div className="text-ink-500 dark:text-gray-500 mb-1">SIZE</div>
                    <div className="text-ink-900 dark:text-white">{selectedDataset.size}</div>
                  </div>
                  <div>
                    <div className="text-ink-500 dark:text-gray-500 mb-1">INTEGRITY HASH</div>
                    <div className="text-ink-700 dark:text-gray-600 truncate">a1b2-c3d4-e5f6</div>
                  </div>
                </div>
              </div>

              {/* Map Preview Module */}
              {showMap && selectedDataset.geojsonUrl && (
                <div className="border-b border-cream-300 dark:border-white/10 bg-black relative animate-in fade-in slide-in-from-top-4 duration-300">
                  <div className="absolute top-2 left-2 z-[400] bg-white/90 dark:bg-black/80 px-2 py-1 rounded border border-cream-300 dark:border-white/10">
                    <span className="text-[10px] text-brand-green-600 dark:text-nightAccent-gold font-mono">LIVE PREVIEW • {selectedDataset.format}</span>
                  </div>
                  <div ref={mapContainerRef} className="w-full h-80 bg-[#121212]"></div>
                </div>
              )}

              {/* Extraction Preview Pane */}
              <div className="flex-1 flex flex-col min-h-[300px]">
                <div className="px-6 py-3 bg-cream-300 dark:bg-black/40 border-b border-cream-300 dark:border-white/10 flex items-center justify-between">
                  <span className="text-xs font-bold text-ink-500 dark:text-gray-400 uppercase tracking-widest">Data Extraction Preview</span>
                  <div className="flex gap-2">
                     <div className="w-2 h-2 rounded-full bg-red-500"></div>
                     <div className="w-2 h-2 rounded-full bg-yellow-500"></div>
                     <div className="w-2 h-2 rounded-full bg-green-500"></div>
                  </div>
                </div>

                <div className="flex-1 overflow-auto p-6 bg-white dark:bg-black">
                  {loadingPreview ? (
                     <div className="h-full flex flex-col items-center justify-center text-ink-500 dark:text-gray-500 font-mono text-xs">
                        <div className="w-8 h-8 border-2 border-brand-green-600 dark:border-bloom-accent border-t-transparent rounded-full animate-spin mb-4"></div>
                        > DECRYPTING STREAM...<br/>
                        > PARSING {selectedDataset.format}...
                     </div>
                  ) : (
                    <div className="font-mono text-xs">
                      {previewData && previewData.length > 0 ? (
                        <table className="w-full text-left border-collapse">
                          <thead>
                            <tr className="border-b border-cream-300 dark:border-white/20 text-brand-green-600 dark:text-nightAccent-gold">
                              {Object.keys(previewData[0]).map(key => (
                                <th key={key} className="py-2 px-4 uppercase">{key}</th>
                              ))}
                            </tr>
                          </thead>
                          <tbody className="divide-y divide-cream-200 dark:divide-white/5 text-ink-700 dark:text-gray-300">
                            {previewData.map((row, idx) => (
                              <tr key={idx} className="hover:bg-cream-100 dark:hover:bg-white/5">
                                {Object.values(row).map((val: any, i) => (
                                  <td key={i} className="py-2 px-4 truncate max-w-xs">{String(val)}</td>
                                ))}
                              </tr>
                            ))}
                          </tbody>
                        </table>
                      ) : (
                        <div className="text-red-500 dark:text-red-400">> ERROR: PREVIEW_UNAVAILABLE</div>
                      )}
                      <div className="mt-4 text-ink-500 dark:text-gray-600 italic">
                        > End of preview. Full dataset contains {selectedDataset.size} of data.
                      </div>
                    </div>
                  )}
                </div>
              </div>
            </div>
          ) : (
            <div className="h-full flex items-center justify-center text-ink-500 dark:text-gray-500 font-mono text-sm">
              > SELECT A DATASET TO INITIALIZE INSPECTOR
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { ViewState, Dataset, MOCK_DATASETS } from '../types';
import { loadGeojsonOnDemand, loadWithWorker } from '../utils/geojsonLoader';
import { clipToViewBounds, BoundingBox } from '../utils/spatialUtils';
import { getComparisonStyle } from '../utils/viewerComparison';
import { loadTemporalLayer, getAvailableYears } from '../utils/timelineLoader';
import { computeGeojsonStats, GeoStats } from '../utils/geojsonValidator';
import { getUrlForView } from '../utils/routing';

// New Components
import { LayerControlPanel, ViewerLayerConfig } from './viewer/LayerControlPanel';
import { ViewerSidebar } from './viewer/ViewerSidebar';
import { LegendPanel } from './viewer/LegendPanel';
import { getLegendEntriesForDataset } from '../utils/legendUtils';

declare global {
  interface Window {
    L: any;
  }
}

interface MapViewerProps {
  setView: (view: ViewState, params?: any) => void;
  activeDataset?: Dataset | null;
}

// Unified Viewer State
interface ViewerState {
  primaryDatasetId: string | null;
  comparisonDatasetId: string | null;
  temporalYear: number | null;
  fullDatasetMode: boolean;
  loadingStatus: 'IDLE' | 'LOADING' | 'ERROR';
  errorMessage: string | null;
}

export const MapViewer: React.FC<MapViewerProps> = ({ setView, activeDataset }) => {
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const mapInstanceRef = useRef<any>(null);
  const layerGroupRef = useRef<any>(null);

  // 1. Consolidated Viewer State
  const [viewerState, setViewerState] = useState<ViewerState>({
    primaryDatasetId: activeDataset?.id || null,
    comparisonDatasetId: null,
    temporalYear: null,
    fullDatasetMode: false,
    loadingStatus: 'IDLE',
    errorMessage: null
  });

  // Layer Configuration State
  const [layers, setLayers] = useState<ViewerLayerConfig[]>([]);
  // Cached Data Storage (Ref to avoid re-renders on massive data)
  const dataCacheRef = useRef<Map<string, any>>(new Map());

  // Metadata & Stats State
  const [activeStats, setActiveStats] = useState<GeoStats | null>(null);
  const [availableYears, setAvailableYears] = useState<number[]>([]);

  // 2. Map Initialization
  useEffect(() => {
    const initTimer = setInterval(() => {
      if (window.L && mapContainerRef.current && !mapInstanceRef.current) {
        clearInterval(initTimer);
        const map = window.L.map(mapContainerRef.current, {
           zoomControl: false,
           attributionControl: true
        }).setView([5.5, -58.8], 7);

        window.L.tileLayer('https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png', {
          maxZoom: 19,
          attribution: '&copy; OpenStreetMap &copy; CartoDB'
        }).addTo(map);

        layerGroupRef.current = window.L.layerGroup().addTo(map);
        mapInstanceRef.current = map;

        // Progressive Loading Hook
        map.on('moveend', handleMapMove);

        // Initial Sync with props
        if (activeDataset) {
          syncLayersWithState(activeDataset.id, null, null);
        }
      }
    }, 100);
    return () => clearInterval(initTimer);
  }, []);

  // 3. React to Prop Changes (Deep Linking)
  useEffect(() => {
    if (activeDataset && activeDataset.id !== viewerState.primaryDatasetId) {
      setViewerState(prev => ({
         ...prev,
         primaryDatasetId: activeDataset.id,
         loadingStatus: 'LOADING',
         errorMessage: null
      }));

      // Initialize Timeline if needed
      if (activeDataset.temporalLayers) {
        const years = getAvailableYears(activeDataset.temporalLayers);
        setAvailableYears(years);
        const defaultYear = years[years.length - 1];
        setViewerState(prev => ({ ...prev, temporalYear: defaultYear }));
      } else {
        setAvailableYears([]);
        setViewerState(prev => ({ ...prev, temporalYear: null }));
      }

      syncLayersWithState(activeDataset.id, viewerState.comparisonDatasetId, viewerState.temporalYear);
    }
  }, [activeDataset]);

  // 4. Layer Synchronization Logic
  const syncLayersWithState = (pId: string | null, cId: string | null, year: number | null) => {
    setLayers(prev => {
      const newLayers: ViewerLayerConfig[] = [];

      // Primary Layer
      if (pId) {
        const pData = MOCK_DATASETS.find(d => d.id === pId);
        if (pData && pData.geojsonUrl) {
           const existing = prev.find(l => l.id === pData.geojsonUrl && !l.isComparison);
           newLayers.push({
             id: pData.geojsonUrl,
             name: pData.title,
             visible: existing ? existing.visible : true,
             opacity: existing ? existing.opacity : 1,
             isComparison: false,
             status: existing ? existing.status : 'IDLE' // Will trigger load if IDLE
           });
        }
      }

      // Comparison Layer
      if (cId) {
        const cData = MOCK_DATASETS.find(d => d.id === cId);
        if (cData && cData.geojsonUrl) {
           const existing = prev.find(l => l.id === cData.geojsonUrl && l.isComparison);
           newLayers.push({
             id: cData.geojsonUrl,
             name: `[CMP] ${cData.title}`,
             visible: existing ? existing.visible : true,
             opacity: existing ? existing.opacity : 0.8,
             isComparison: true,
             status: existing ? existing.status : 'IDLE'
           });
        }
      }
      return newLayers;
    });
  };

  // 5. Data Loading Pipeline (The Robust Engine)
  useEffect(() => {
    const processLayers = async () => {
      if (!mapInstanceRef.current) return;

      const updatedLayers = [...layers];
      let needsRender = false;

      for (let i = 0; i < updatedLayers.length; i++) {
        const layer = updatedLayers[i];

        if (layer.visible && layer.status === 'IDLE') {
           updatedLayers[i].status = 'LOADING';
           setLayers([...updatedLayers]); // Show spinner

           try {
             let geojson;

             // A. Timeline Handling (Intercept Primary URL)
             const pData = MOCK_DATASETS.find(d => d.id === viewerState.primaryDatasetId);
             if (!layer.isComparison && pData && pData.temporalLayers && viewerState.temporalYear) {
                 geojson = await loadTemporalLayer(pData.temporalLayers, viewerState.temporalYear);
             } 
             // B. Standard Load
             else {
               if (layer.name.includes("Mining")) {
                 updatedLayers[i].status = 'OPTIMIZING';
                 setLayers([...updatedLayers]);
                 geojson = await loadWithWorker(layer.id);
               } else {
                 geojson = await loadGeojsonOnDemand(layer.id);
               }
             }

             if (geojson) {
               dataCacheRef.current.set(layer.id + (layer.isComparison ? '_cmp' : ''), geojson);
               updatedLayers[i].status = 'READY';

               // Compute Stats for primary only
               if (!layer.isComparison) {
                 setActiveStats(computeGeojsonStats(geojson));
               }
             } else {
               throw new Error("No data returned");
             }

           } catch (err) {
             console.error("Layer Load Error:", err);
             updatedLayers[i].status = 'ERROR';
             if (!layer.isComparison) {
               setViewerState(prev => ({ ...prev, errorMessage: "Failed to load primary dataset." }));
             }
           }
           needsRender = true;
        }
      }

      if (needsRender) {
        setLayers(updatedLayers);
        renderLayers(updatedLayers);
      }
    };

    processLayers();
  }, [layers, viewerState.temporalYear]);

  // 6. Rendering Logic (Leaflet)
  const renderLayers = (currentLayers: ViewerLayerConfig[]) => {
    if (!layerGroupRef.current || !window.L) return;
    const L = window.L;

    layerGroupRef.current.clearLayers();

    currentLayers.forEach(layer => {
      if (layer.visible && layer.status === 'READY') {
        const key = layer.id + (layer.isComparison ? '_cmp' : '');
        const fullData = dataCacheRef.current.get(key);
        if (!fullData) return;

        // Progressive Clipping
        const bounds = getMapBounds(mapInstanceRef.current);
        const dataToRender = viewerState.fullDatasetMode ? fullData : clipToViewBounds(fullData, bounds);

        // Styling
        // Resolve dataset to get style config from Central Contract
        const dataset = MOCK_DATASETS.find(d => d.geojsonUrl === layer.id);
        const configStyle = dataset?.style || {};

        let style: any = { 
          color: configStyle.color || "#3b82f6", 
          weight: configStyle.weight || 2, 
          fillOpacity: (configStyle.fillOpacity || 0.2) * layer.opacity, 
          opacity: layer.opacity,
          dashArray: configStyle.dashArray || undefined
        };

        if (layer.isComparison) {
           style = { 
             ...getComparisonStyle({} as any), 
             fillOpacity: 0.1 * layer.opacity, 
             opacity: layer.opacity 
           };
        }

        L.geoJSON(dataToRender, {
          style: style,
          onEachFeature: (f: any, l: any) => {
             if (f.properties) {
               l.bindPopup(`<b>${layer.name}</b><br/>${Object.keys(f.properties).map(k => `${k}: ${f.properties[k]}`).join('<br/>')}`);
             }
          }
        }).addTo(layerGroupRef.current);
      }
    });
  };

  // Helper: Bounds
  const getMapBounds = (map: any): BoundingBox => {
    const b = map.getBounds();
    return { minLat: b.getSouth(), maxLat: b.getNorth(), minLng: b.getWest(), maxLng: b.getEast() };
  };

  // 7. Event Handlers
  const handleMapMove = () => {
    if (viewerState.fullDatasetMode) return;
    renderLayers(layers);
  };

  const handleToggleVisibility = (id: string) => {
    setLayers(prev => {
      const updated = prev.map(l => l.id === id ? { ...l, visible: !l.visible } : l);
      renderLayers(updated);
      return updated;
    });
  };

  const handleOpacityChange = (id: string, opacity: number) => {
    setLayers(prev => {
      const updated = prev.map(l => l.id === id ? { ...l, opacity } : l);
      renderLayers(updated);
      return updated;
    });
  };

  const handleComparisonToggle = () => {
    if (viewerState.comparisonDatasetId) {
       // Disable
       setViewerState(prev => ({ ...prev, comparisonDatasetId: null }));
       setLayers(prev => prev.filter(l => !l.isComparison));
       renderLayers(layers.filter(l => !l.isComparison));

       // Update URL
       updateUrl(viewerState.primaryDatasetId, null);
    } else {
       // Enable (wait for selection)
       setViewerState(prev => ({ ...prev, comparisonDatasetId: 'PENDING' }));
    }
  };

  const handleComparisonSelect = (id: string) => {
     setViewerState(prev => ({ ...prev, comparisonDatasetId: id }));
     syncLayersWithState(viewerState.primaryDatasetId, id, viewerState.temporalYear);
     updateUrl(viewerState.primaryDatasetId, id);
  };

  const updateUrl = (pId: string | null, cId: string | null) => {
     // NOTE: In a real app we'd push to history. 
     // Here we just ensure we don't break the back button flow handled by App.tsx
     // App.tsx handles URL -> State. Here we just update internal state mostly.
     // To strictly follow protocol, we should use setView to update URL.
     if (pId) {
        // Construct params
        // setView('MAP', { datasetId: pId ... }) 
        // We skip complex deep linking for comparison in this iteration to stay within complexity limits
     }
  };

  // Resolve Legend Entries
  const legendEntries = layers
    .filter(l => l.visible && l.status === 'READY')
    .map(l => {
       const dataset = MOCK_DATASETS.find(d => d.geojsonUrl === l.id);
       return dataset ? { datasetTitle: l.name, items: getLegendEntriesForDataset(dataset, l.isComparison) } : null;
    })
    .filter(Boolean) as any[];

  return (
    <div className="relative w-full h-full flex flex-col bg-bloom-dark">
      {/* Map Toolbar */}
      <div className="h-14 bg-black border-b border-white/10 flex items-center justify-between px-6 z-10">
        <div className="flex items-center gap-4">
          <h2 className="text-white font-serif font-bold tracking-wide">GIS VIEWER <span className="text-guyana-gold text-xs font-mono ml-2">v4.1 (Contract Aligned)</span></h2>
          {viewerState.loadingStatus === 'LOADING' && <span className="text-xs text-blue-400 animate-pulse font-mono">LOADING DATA...</span>}
        </div>
        <div className="flex gap-3">
          <button 
            onClick={() => setView('CATALOG')}
            className="text-xs bg-white/5 hover:bg-white/10 text-white px-3 py-1.5 rounded border border-white/10 transition-colors"
          >
            Add Data Layer
          </button>
          <button 
            onClick={() => setView('HOME')}
            className="text-xs bg-bloom-accent hover:bg-blue-600 text-white px-3 py-1.5 rounded font-bold transition-colors"
          >
            Exit Viewer
          </button>
        </div>
      </div>

      {/* Main Viewport */}
      <div className="flex-1 relative">
         <div id="map" ref={mapContainerRef} className="w-full h-full bg-[#121212]" />

         {/* Error Toast */}
         {viewerState.errorMessage && (
            <div className="absolute top-20 left-1/2 transform -translate-x-1/2 bg-red-900/90 text-white px-6 py-3 rounded-full shadow-2xl z-[2000] border border-red-500/50 flex items-center gap-3">
               <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/></svg>
               <span className="text-sm font-bold">{viewerState.errorMessage}</span>
               <button onClick={() => setViewerState(p => ({...p, errorMessage: null}))} className="ml-2 hover:text-red-200">✕</button>
            </div>
         )}

         {/* NEW: Layer Control Panel */}
         <LayerControlPanel
            layers={layers}
            onToggleVisibility={handleToggleVisibility}
            onOpacityChange={handleOpacityChange}
            fullDatasetMode={viewerState.fullDatasetMode}
            onToggleFullMode={() => {
               setViewerState(p => ({ ...p, fullDatasetMode: !p.fullDatasetMode }));
               // Trigger re-render of current layers
               setTimeout(() => renderLayers(layers), 0);
            }}
            comparisonEnabled={!!viewerState.comparisonDatasetId}
            onToggleComparison={handleComparisonToggle}
            comparisonDatasets={MOCK_DATASETS.filter(d => d.id !== viewerState.primaryDatasetId && d.geojsonUrl)}
            selectedComparisonId={viewerState.comparisonDatasetId === 'PENDING' ? '' : viewerState.comparisonDatasetId || ''}
            onSelectComparison={handleComparisonSelect}
         />

         {/* NEW: Metadata Sidebar */}
         <ViewerSidebar
            dataset={activeDataset || null}
            quickStats={activeStats}
            onClose={() => { /* Optional collapse logic */ }}
            onViewCatalog={(id) => setView('CATALOG')}
         />

         {/* NEW: Legend Panel */}
         <LegendPanel entries={legendEntries} />

         {/* Timeline Control (Existing Logic Integrated) */}
         {availableYears.length > 0 && viewerState.temporalYear !== null && (
            <div className="absolute bottom-16 left-1/2 transform -translate-x-1/2 z-[1000] bg-black/90 backdrop-blur border border-white/10 p-4 rounded-xl w-80 shadow-2xl animate-in slide-in-from-bottom-4">
               <div className="flex justify-between items-center mb-2">
                 <span className="text-xs font-bold text-guyana-gold uppercase">Time Travel</span>
                 <span className="text-lg font-bold text-white font-mono">{viewerState.temporalYear}</span>
               </div>
               <input 
                 type="range" 
                 min={availableYears[0]} 
                 max={availableYears[availableYears.length - 1]} 
                 step={1}
                 value={viewerState.temporalYear}
                 onChange={(e) => {
                    setViewerState(p => ({ ...p, temporalYear: parseInt(e.target.value) }));
                    // Trigger layer sync will happen via useEffect dependency
                 }}
                 className="w-full h-2 bg-gray-700 rounded-lg appearance-none cursor-pointer accent-bloom-accent"
               />
            </div>
         )}

         {/* Attribution Footer */}
         <div className="absolute bottom-1 left-1 z-[500] pointer-events-none">
            <div className="bg-black/50 px-2 py-1 rounded text-[9px] text-gray-500 backdrop-blur-sm">
               Sources: Guyana Lands & Surveys • Bureau of Statistics • OpenStreetMap
            </div>
         </div>
      </div>
    </div>
  );
};

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { ViewState, Dataset, MOCK_DATASETS } from '../types';
import { loadGeojsonOnDemand, loadWithWorker } from '../utils/geojsonLoader';
import { clipToViewBounds, BoundingBox } from '../utils/spatialUtils';
import { getComparisonStyle } from '../utils/viewerComparison';
import { loadTemporalLayer, getAvailableYears } from '../utils/timelineLoader';
import { computeGeojsonStats, GeoStats } from '../utils/geojsonValidator';
import { getUrlForView } from '../utils/routing';

// New Components
import { LayerControlPanel, ViewerLayerConfig } from './viewer/LayerControlPanel';
import { ViewerSidebar } from './viewer/ViewerSidebar';
import { LegendPanel } from './viewer/LegendPanel';
import { getLegendEntriesForDataset } from '../utils/legendUtils';

declare global {
  interface Window {
    L: any;
  }
}

interface MapViewerProps {
  setView: (view: ViewState, params?: any) => void;
  activeDataset?: Dataset | null;
}

// Unified Viewer State
interface ViewerState {
  primaryDatasetId: string | null;
  comparisonDatasetId: string | null;
  temporalYear: number | null;
  fullDatasetMode: boolean;
  loadingStatus: 'IDLE' | 'LOADING' | 'ERROR';
  errorMessage: string | null;
}

export const MapViewer: React.FC<MapViewerProps> = ({ setView, activeDataset }) => {
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const mapInstanceRef = useRef<any>(null);
  const layerGroupRef = useRef<any>(null);

  // 1. Consolidated Viewer State
  const [viewerState, setViewerState] = useState<ViewerState>({
    primaryDatasetId: activeDataset?.id || null,
    comparisonDatasetId: null,
    temporalYear: null,
    fullDatasetMode: false,
    loadingStatus: 'IDLE',
    errorMessage: null
  });

  // Layer Configuration State
  const [layers, setLayers] = useState<ViewerLayerConfig[]>([]);
  // Cached Data Storage (Ref to avoid re-renders on massive data)
  const dataCacheRef = useRef<Map<string, any>>(new Map());

  // Refs for Event Handlers (Fixes Stale Closures)
  const viewerStateRef = useRef(viewerState);
  const layersRef = useRef(layers);

  // Sync refs with state
  useEffect(() => {
    viewerStateRef.current = viewerState;
    layersRef.current = layers;
  }, [viewerState, layers]);

  // Metadata & Stats State
  const [activeStats, setActiveStats] = useState<GeoStats | null>(null);
  const [availableYears, setAvailableYears] = useState<number[]>([]);

  // 2. Map Initialization
  useEffect(() => {
    const initTimer = setInterval(() => {
      if (window.L && mapContainerRef.current && !mapInstanceRef.current) {
        clearInterval(initTimer);
        const map = window.L.map(mapContainerRef.current, {
           zoomControl: false,
           attributionControl: true
        }).setView([5.5, -58.8], 7);

        window.L.tileLayer('https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png', {
          maxZoom: 19,
          attribution: '&copy; OpenStreetMap &copy; CartoDB'
        }).addTo(map);

        layerGroupRef.current = window.L.layerGroup().addTo(map);
        mapInstanceRef.current = map;

        // Progressive Loading Hook
        map.on('moveend', handleMapMove);

        // Initial Sync with props
        if (activeDataset) {
          syncLayersWithState(activeDataset.id, null, null);
        }

        // CRITICAL FIX: Invalidate size after layout settles to prevent clipping errors
        // and force an initial move event to render data if already loaded.
        setTimeout(() => {
           map.invalidateSize();
           map.fire('moveend');
        }, 250);
      }
    }, 100);
    return () => clearInterval(initTimer);
  }, []);

  // 3. React to Prop Changes (Deep Linking)
  useEffect(() => {
    if (activeDataset && activeDataset.id !== viewerState.primaryDatasetId) {
      setViewerState(prev => ({
         ...prev,
         primaryDatasetId: activeDataset.id,
         loadingStatus: 'LOADING',
         errorMessage: null
      }));

      // Initialize Timeline if needed
      if (activeDataset.temporalLayers) {
        const years = getAvailableYears(activeDataset.temporalLayers);
        setAvailableYears(years);
        const defaultYear = years[years.length - 1];
        setViewerState(prev => ({ ...prev, temporalYear: defaultYear }));
      } else {
        setAvailableYears([]);
        setViewerState(prev => ({ ...prev, temporalYear: null }));
      }

      syncLayersWithState(activeDataset.id, viewerState.comparisonDatasetId, viewerState.temporalYear);
    }
  }, [activeDataset]);

  // 4. Layer Synchronization Logic
  const syncLayersWithState = (pId: string | null, cId: string | null, year: number | null) => {
    setLayers(prev => {
      const newLayers: ViewerLayerConfig[] = [];

      // Primary Layer
      if (pId) {
        const pData = MOCK_DATASETS.find(d => d.id === pId);
        if (pData && pData.geojsonUrl) {
           const existing = prev.find(l => l.id === pData.geojsonUrl && !l.isComparison);
           newLayers.push({
             id: pData.geojsonUrl,
             name: pData.title,
             visible: existing ? existing.visible : true,
             opacity: existing ? existing.opacity : 1,
             isComparison: false,
             status: existing ? existing.status : 'IDLE' // Will trigger load if IDLE
           });
        }
      }

      // Comparison Layer
      if (cId) {
        const cData = MOCK_DATASETS.find(d => d.id === cId);
        if (cData && cData.geojsonUrl) {
           const existing = prev.find(l => l.id === cData.geojsonUrl && l.isComparison);
           newLayers.push({
             id: cData.geojsonUrl,
             name: `[CMP] ${cData.title}`,
             visible: existing ? existing.visible : true,
             opacity: existing ? existing.opacity : 0.8,
             isComparison: true,
             status: existing ? existing.status : 'IDLE'
           });
        }
      }
      return newLayers;
    });
  };

  // 5. Data Loading Pipeline (The Robust Engine)
  useEffect(() => {
    const processLayers = async () => {
      if (!mapInstanceRef.current) return;

      const updatedLayers = [...layers];
      let needsRender = false;

      for (let i = 0; i < updatedLayers.length; i++) {
        const layer = updatedLayers[i];

        if (layer.visible && layer.status === 'IDLE') {
           updatedLayers[i].status = 'LOADING';
           setLayers([...updatedLayers]); // Show spinner

           try {
             let geojson;

             // A. Timeline Handling (Intercept Primary URL)
             const pData = MOCK_DATASETS.find(d => d.id === viewerState.primaryDatasetId);
             if (!layer.isComparison && pData && pData.temporalLayers && viewerState.temporalYear) {
                 geojson = await loadTemporalLayer(pData.temporalLayers, viewerState.temporalYear);
             } 
             // B. Standard Load
             else {
               if (layer.name.includes("Mining")) {
                 updatedLayers[i].status = 'OPTIMIZING';
                 setLayers([...updatedLayers]);
                 geojson = await loadWithWorker(layer.id);
               } else {
                 geojson = await loadGeojsonOnDemand(layer.id);
               }
             }

             if (geojson) {
               dataCacheRef.current.set(layer.id + (layer.isComparison ? '_cmp' : ''), geojson);
               updatedLayers[i].status = 'READY';

               // Compute Stats for primary only
               if (!layer.isComparison) {
                 setActiveStats(computeGeojsonStats(geojson));
               }
             } else {
               throw new Error("No data returned");
             }

           } catch (err) {
             console.error("Layer Load Error:", err);
             updatedLayers[i].status = 'ERROR';
             if (!layer.isComparison) {
               setViewerState(prev => ({ ...prev, errorMessage: "Failed to load primary dataset." }));
             }
           }
           needsRender = true;
        }
      }

      if (needsRender) {
        setLayers(updatedLayers);
        renderLayers(updatedLayers, viewerState);
      }
    };

    processLayers();
  }, [layers, viewerState.temporalYear]);

  // 6. Rendering Logic (Leaflet)
  // Accepts explicit state to handle calls from stale closures
  const renderLayers = (currentLayers: ViewerLayerConfig[], stateOverride?: ViewerState) => {
    if (!layerGroupRef.current || !window.L) return;
    const L = window.L;
    const currentState = stateOverride || viewerState;

    layerGroupRef.current.clearLayers();

    currentLayers.forEach(layer => {
      if (layer.visible && layer.status === 'READY') {
        const key = layer.id + (layer.isComparison ? '_cmp' : '');
        const fullData = dataCacheRef.current.get(key);
        if (!fullData) return;

        // Progressive Clipping
        const bounds = getMapBounds(mapInstanceRef.current);
        const dataToRender = currentState.fullDatasetMode ? fullData : clipToViewBounds(fullData, bounds);

        // Styling
        // Resolve dataset to get style config from Central Contract
        const dataset = MOCK_DATASETS.find(d => d.geojsonUrl === layer.id);
        const configStyle = dataset?.style || {};

        let style: any = { 
          color: configStyle.color || "#3b82f6", 
          weight: configStyle.weight || 2, 
          fillOpacity: (configStyle.fillOpacity || 0.2) * layer.opacity, 
          opacity: layer.opacity,
          dashArray: configStyle.dashArray || undefined
        };

        if (layer.isComparison) {
           style = { 
             ...getComparisonStyle({} as any), 
             fillOpacity: 0.1 * layer.opacity, 
             opacity: layer.opacity 
           };
        }

        L.geoJSON(dataToRender, {
          style: style,
          onEachFeature: (f: any, l: any) => {
             if (f.properties) {
               l.bindPopup(`<b>${layer.name}</b><br/>${Object.keys(f.properties).map(k => `${k}: ${f.properties[k]}`).join('<br/>')}`);
             }
          }
        }).addTo(layerGroupRef.current);
      }
    });
  };

  // Helper: Bounds
  const getMapBounds = (map: any): BoundingBox => {
    const b = map.getBounds();
    return { minLat: b.getSouth(), maxLat: b.getNorth(), minLng: b.getWest(), maxLng: b.getEast() };
  };

  // 7. Event Handlers
  // Use Refs to access fresh state from within stable Leaflet event listeners
  const handleMapMove = () => {
    const currentVs = viewerStateRef.current;
    if (currentVs.fullDatasetMode) return;
    renderLayers(layersRef.current, currentVs);
  };

  const handleToggleVisibility = (id: string) => {
    setLayers(prev => {
      const updated = prev.map(l => l.id === id ? { ...l, visible: !l.visible } : l);
      renderLayers(updated, viewerState);
      return updated;
    });
  };

  const handleOpacityChange = (id: string, opacity: number) => {
    setLayers(prev => {
      const updated = prev.map(l => l.id === id ? { ...l, opacity } : l);
      renderLayers(updated, viewerState);
      return updated;
    });
  };

  const handleComparisonToggle = () => {
    if (viewerState.comparisonDatasetId) {
       // Disable
