import React, { useEffect } from 'react';
import { ViewState } from '../../types';
import { RouteParams } from '../../utils/routing';
import { updateMetadata, DEFAULT_TITLE } from '../../utils/meta';

interface MetaManagerProps {
  view: ViewState;
  params: RouteParams;
}

export const MetaManager: React.FC<MetaManagerProps> = ({ view, params }) => {
  useEffect(() => {
    // Basic title override for views not fully handled by utils/meta.ts
    // This serves as a safety net before updateMetadata takes over
    const suffix = 'GuyNode Spatial Hub';
    let title = DEFAULT_TITLE;

    switch (view) {
      case 'HOME': title = `Home | ${suffix}`; break;
      case 'CATALOG': title = `Data Catalog | ${suffix}`; break;
      case 'MAP': title = `GIS Viewer | ${suffix}`; break;
      case 'DOCS': title = `Developers | ${suffix}`; break;
      case 'ANALYSIS': title = `Analysis | ${suffix}`; break;
      case 'ABOUT': title = `About | ${suffix}`; break;
      case 'SUPPORT': title = `Support & Legal | ${suffix}`; break;
      case 'REPORT_ISSUE': title = `Report Issue | ${suffix}`; break;
      case 'BLOG_INDEX': title = `Blog | ${suffix}`; break;
      case 'BLOG_POST': title = `Blog Post | ${suffix}`; break;
      case 'ADMIN_ACCESS': title = `Dev Tools | ${suffix}`; break;
      case 'INTERNAL_LOG': title = `Internal Log | ${suffix}`; break;
      case 'CHANGELOG': title = `Changelog | ${suffix}`; break;
      case 'TRIAGE_PROMPT_LIBRARY': title = `Triage Library | ${suffix}`; break;
    }

    if (document.title !== title) {
      document.title = title;
    }

    // Call the detailed metadata updater
    updateMetadata(view, params);
  }, [view, params]);

  return null;
};

import React, { useState, useEffect } from 'react';
