                    <div className="grid grid-cols-2 gap-4">
                      <input type="text" placeholder="First Name" className="border border-gn-border dark:border-gn-border-dark bg-gn-surface-elevated dark:bg-gn-surface-elevated-dark p-3 rounded w-full focus:outline-none focus:border-brand-green-500" />
                      <input type="text" placeholder="Last Name" className="border border-gn-border dark:border-gn-border-dark bg-gn-surface-elevated dark:bg-gn-surface-elevated-dark p-3 rounded w-full focus:outline-none focus:border-brand-green-500" />
                    </div>
                    <input type="email" placeholder="Business Email" className="border border-gn-border dark:border-gn-border-dark bg-gn-surface-elevated dark:bg-gn-surface-elevated-dark p-3 rounded w-full focus:outline-none focus:border-brand-green-500" />
                    <select className="border border-gn-border dark:border-gn-border-dark bg-gn-surface-elevated dark:bg-gn-surface-elevated-dark p-3 rounded w-full focus:outline-none focus:border-brand-green-500">
                      <option>Select Industry...</option>
                      <option>Energy</option>
                      <option>Agriculture</option>
                      <option>Mining</option>
                      <option>Government</option>
                    </select>
                    <button className="bg-brand-green-600 hover:bg-brand-green-500 dark:bg-nightAccent-green dark:hover:bg-brand-green-500 text-white font-bold py-4 rounded w-full transition-colors">
                      Submit Request
                    </button>
                    <p className="text-xs text-gn-foreground-muted dark:text-gn-foreground-muted-dark mt-4">
                      By submitting this form, you agree to our Privacy Policy.
                    </p>
                 </div>
              </div>
            </section>
          </>
        );
      case 'CATALOG':
        return <Catalog onOpenMap={handleOpenMap} />;
      case 'MAP':
        return (
          <GisViewerPage setView={(v) => handleNavigation(v)} activeDataset={activeMapDataset} />
        );
      case 'DOCS':
        return <DevelopersPage />;

      case 'ANALYSIS':
        // If an ID is present, show detail view, else show index
        if (currentParams.analysisId) {
          return <AnalysisDetailPage analysisId={currentParams.analysisId} navigate={handleNavigation} />;
        }
        return <AnalysisPage navigate={handleNavigation} />;

      case 'ABOUT':
        return <About />;

      case 'SUPPORT':
        return <SupportPage navigate={handleNavigation} section={currentParams.supportSection} />;

      case 'REPORT_ISSUE':
        return <ReportIssuePage navigate={handleNavigation} />;

      case 'INTERNAL_LOG':
        return <InternalLogPage />;
      case 'CHANGELOG':
        return <ChangelogPage />;

      // Blog Module Routes
      case 'BLOG_INDEX':
        return <BlogIndexPage navigate={navigateToBlog} />;
      case 'BLOG_POST':
        return <BlogPostPage navigate={navigateToBlog} params={currentParams} onOpenMap={handleOpenMapById} />;
      case 'BLOG_CATEGORY':
        return <BlogCategoryPage navigate={navigateToBlog} params={currentParams} />;
      case 'BLOG_ARCHIVE':
        return <BlogArchivePage navigate={navigateToBlog} params={currentParams} />;
      case 'BLOG_SEARCH':
        return <BlogSearchPage navigate={navigateToBlog} />;

      // Admin Routes
      case 'ADMIN_ACCESS':
        return <AdminAccessPage navigate={(v, p) => handleNavigation(v, p)} params={currentParams} />;
      case 'TRIAGE_PROMPT_LIBRARY':
        return <TriagePromptLibraryPage navigate={(v) => handleNavigation(v)} />;

      default:
        return <div>Page Not Found</div>;
    }
  };

  return (
    <>
      <MetaManager view={currentView} params={currentParams} />
      <div className="min-h-screen bg-gn-surface dark:bg-gn-surface-dark text-gn-foreground dark:text-gn-foreground-dark selection:bg-brand-gold-500 selection:text-ink-900 relative transition-colors duration-300">
        <Navigation 
          currentView={currentView} 
          setView={(v) => handleNavigation(v)} 
          theme={theme}
          toggleTheme={toggleTheme}
        />

        {redirectNotification && (
          <div className="fixed top-20 left-1/2 transform -translate-x-1/2 z-[100] bg-red-900/90 text-white px-6 py-3 rounded-full shadow-2xl border border-red-500/30 flex items-center gap-3 animate-in fade-in slide-in-from-top-4 duration-300">
             <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/></svg>
             <span className="text-sm font-medium">{redirectNotification}</span>
          </div>
        )}

        <main>
          {renderContent()}
        </main>
        <Footer setView={(v, p) => handleNavigation(v, p)} />
        <Assistant />
      </div>
    </>
  );
}

