            <p className="text-sm text-gray-400">
              Internal diagnostic and logging tools.<br />
              <span className="text-[10px] uppercase tracking-widest text-guyana-gold font-mono block mt-2">
                (Client-Side Soft Gate Only)
              </span>
            </p>
          </div>

          <form onSubmit={handleLogin} className="space-y-4">
            <div>
              <input 
                type="password" 
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                placeholder="Dev Password"
                className="w-full bg-black/50 border border-white/20 rounded px-4 py-3 text-white focus:outline-none focus:border-bloom-accent text-center"
                autoFocus
              />
            </div>
            {error && <p className="text-red-400 text-xs text-center">{error}</p>}
            <button 
              type="submit"
              className="w-full bg-bloom-accent hover:bg-blue-600 text-white font-bold py-3 rounded transition-colors"
            >
              Unlock Console
            </button>
          </form>

          <div className="mt-6 text-center">
            <button onClick={() => navigate('HOME')} className="text-xs text-gray-500 hover:text-white">
              ← Return to Public Site
            </button>
          </div>
        </div>
      </div>
    );
  }

  if (showConsole) {
    return (
      <div className="relative">
        <div className="bg-red-900/50 text-white text-center text-xs font-bold py-1 border-b border-red-500/30 uppercase tracking-widest">
          Developer Mode • Do NOT enter real user data
        </div>
        <AdminConsole 
          navigate={navigate} 
          activeSection={params?.adminSection} 
        />
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-black text-white pt-20 px-6">
      {/* Banner */}
      <div className="fixed top-16 left-0 w-full bg-stripes-gray z-40 pointer-events-none opacity-5 h-2"></div>

      <div className="max-w-6xl mx-auto">
        <header className="flex justify-between items-center mb-12 border-b border-white/10 pb-6">
          <div>
            <div className="flex items-center gap-3 mb-2">
               <span className="bg-yellow-500/20 text-yellow-500 border border-yellow-500/30 text-[10px] font-bold px-2 py-0.5 rounded">SANDBOX MODE</span>
            </div>
            <h1 className="text-3xl font-serif font-bold text-white">Dev Dashboard</h1>
            <p className="text-gray-400 text-sm mt-1">Guynode Studio Internal Tools</p>
          </div>
          <button 
            onClick={handleLock} 
            className="text-xs font-mono text-gray-500 hover:text-white border border-white/10 px-3 py-1 rounded"
          >
            LOCK SESSION
          </button>
        </header>

        <div className="bg-blue-900/10 border border-blue-500/20 p-4 rounded-lg mb-8 text-sm text-blue-200">
           <strong>Security Note:</strong> This dashboard is a client-side utility for diagnostics (logging, prompt triage, link checking). It does not provide administrative control over the backend or database. Do not use this interface to store sensitive credentials or PII.
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-8 mb-12">

