        if (currentParams.analysisId) {
          return <AnalysisDetailPage analysisId={currentParams.analysisId} navigate={handleNavigation} />;
        }
        return <AnalysisPage navigate={handleNavigation} />;

      case 'ABOUT':
        return <About />;

      case 'SUPPORT':
        return <SupportPage navigate={handleNavigation} section={currentParams.supportSection} />;

      case 'REPORT_ISSUE':
