  }

  return (
    <div className="absolute top-20 left-6 z-[1000] bg-black/90 backdrop-blur border border-white/10 rounded-lg w-80 shadow-2xl flex flex-col max-h-[80vh] animate-in slide-in-from-left-4">

      {/* Header */}
      <div className="p-4 border-b border-white/10 flex justify-between items-start">
         <div>
            <span className="text-[10px] font-bold text-guyana-gold uppercase tracking-widest">{dataset.category}</span>
            <h3 className="text-lg font-serif font-bold text-white leading-tight mt-1">{dataset.title}</h3>
