           <div className="bg-white/5 rounded p-2 border border-white/5">
              <div className="text-[9px] text-gray-500 uppercase mb-1">Source</div>
              <div className="text-xs text-white font-semibold truncate" title={dataset.source}>{dataset.source}</div>
           </div>
           <div className="bg-white/5 rounded p-2 border border-white/5">
              <div className="text-[9px] text-gray-500 uppercase mb-1">Updated</div>
              <div className="text-xs text-white font-semibold">{new Date(dataset.lastUpdated).toLocaleDateString()}</div>
