                    <div className="text-lg font-mono text-white font-bold">{quickStats.geometryTypes.length}</div>
                    <div className="text-[9px] text-gray-500">TYPES</div>
                 </div>
                 <div className="text-center">
                    <div className={`text-lg font-mono font-bold ${quickStats.performanceRisk === 'LOW' ? 'text-green-500' : 'text-yellow-500'}`}>
