import React, { useState, useEffect } from 'react';
import { Dataset, SearchResult, DataCategory, DatasetAsset } from '../types';
import { DataPipeline } from '../services/dataPipeline';
import { SearchEngine } from '../services/searchEngine';
import { CatalogCard } from './CatalogCard';

interface CatalogProps {
  onOpenMap?: (dataset: Dataset) => void;
}

export const Catalog: React.FC<CatalogProps> = ({ onOpenMap }) => {
  // Data State
  const [datasets, setDatasets] = useState<Dataset[]>([]);
  const [filteredResults, setFilteredResults] = useState<SearchResult[]>([]);
  const [loading, setLoading] = useState(true);

  // Filter State
  const [searchQuery, setSearchQuery] = useState('');
  const [activeCategory, setActiveCategory] = useState<DataCategory | 'ALL'>('ALL');

  // Selection & Detail State
  const [selectedDataset, setSelectedDataset] = useState<Dataset | null>(null);
  const [previewData, setPreviewData] = useState<any[] | null>(null);
  const [loadingPreview, setLoadingPreview] = useState(false);

  // Initial Data Ingestion (Section 7)
  useEffect(() => {
    const loadData = async () => {
      setLoading(true);
      try {
        const data = await DataPipeline.ingestCatalog();
        setDatasets(data);
        // Initial filter
        if (data.length > 0) setSelectedDataset(data[0]);
      } catch (err) {
        console.error("Ingestion Pipeline Failed", err);
      } finally {
        setLoading(false);
      }
    };
    loadData();
  }, []);

  // Search & Filter Logic (Section 8)
  useEffect(() => {
    // 1. Full text search
    let results = SearchEngine.search(datasets, searchQuery);

    // 2. Category Filter
    if (activeCategory !== 'ALL') {
      results = results.filter(r => r.item.category === activeCategory);
    }

    setFilteredResults(results);
  }, [searchQuery, activeCategory, datasets]);

  // Extraction Logic on Selection
  useEffect(() => {
    if (selectedDataset) {
      const fetchPreview = async () => {
        setLoadingPreview(true);
        setPreviewData(null);
        try {
          const extracted = await DataPipeline.extractPreview(selectedDataset);
          setPreviewData(extracted);
        } catch (e) {
          console.error("Extraction Failed", e);
        } finally {
          setLoadingPreview(false);
        }
      };
      fetchPreview();
    }
  }, [selectedDataset]);

  const handleAssetAction = (asset: DatasetAsset, action: 'view' | 'download') => {
    if (action === 'download') {
      const link = document.createElement('a');
      link.href = asset.storagePath || asset.originalUrl;
      link.download = asset.label;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    } else if (action === 'view') {
      if (asset.type === 'pdf' || asset.type === 'image') {
        window.open(asset.storagePath || asset.originalUrl, '_blank', 'noopener,noreferrer');
      } else if (asset.type === 'geojson' && onOpenMap && selectedDataset) {
        // Special case: if viewing a GeoJSON asset, try to open the main dataset in map
        onOpenMap(selectedDataset); 
      }
    }
  };

  return (
    <div className="min-h-screen bg-cream-100 dark:bg-black pt-4 pb-12 flex flex-col h-screen overflow-hidden transition-colors duration-300">
      {/* Header Bar */}
      <div className="px-6 pb-4 border-b border-cream-300 dark:border-nightBorder-600 bg-cream-100 dark:bg-black z-10 space-y-4">
        <div className="flex justify-between items-center">
          <div>
            <h2 className="text-2xl font-serif font-bold text-ink-900 dark:text-white tracking-tight">Data Catalog <span className="text-brand-green-600 dark:text-nightAccent-green">Terminal</span></h2>
            <div className="text-[10px] text-ink-500 dark:text-gray-500 font-mono mt-1">
              CONNECTED: GUYNODE_MAINNET • LATENCY: 24ms • INGESTION: ACTIVE
            </div>
          </div>
          <div className="flex flex-col gap-2 items-end">
            <input 
              type="text" 
              placeholder="> SEARCH DATASETS..." 
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="bg-cream-200 dark:bg-nightBg-800 border border-cream-300 dark:border-nightBorder-600 rounded-sm px-4 py-2 text-sm text-ink-900 dark:text-nightAccent-gold font-mono focus:border-brand-green-500 dark:focus:border-bloom-accent outline-none w-80 uppercase placeholder-ink-500 dark:placeholder-gray-600" 
            />
            {/* Place Finder Stub */}
            <div className="text-[9px] text-ink-500 dark:text-gray-600 font-mono flex items-center gap-1">
               <span className="w-1.5 h-1.5 rounded-full bg-gray-500"></span>
               Place Finder (Geocoding) coming in v4.2
            </div>
          </div>
        </div>

        {/* Category Chips */}
        <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide">
          <button 
            onClick={() => setActiveCategory('ALL')}
            className={`px-4 py-1 rounded-full text-xs font-bold border transition-colors ${activeCategory === 'ALL' ? 'bg-ink-900 text-cream-100 border-ink-900 dark:bg-white dark:text-black dark:border-white' : 'text-ink-500 border-cream-300 hover:border-ink-900 dark:text-gray-400 dark:border-white/20 dark:hover:border-white'}`}
          >
            ALL
          </button>
          {Object.values(DataCategory).map(cat => (
             <button 
              key={cat}
              onClick={() => setActiveCategory(cat)}
              className={`px-4 py-1 rounded-full text-xs font-bold border transition-colors whitespace-nowrap ${activeCategory === cat ? 'bg-brand-green-600 text-white border-brand-green-600 dark:bg-nightAccent-green dark:text-white dark:border-nightAccent-green' : 'text-ink-500 border-cream-300 hover:border-brand-green-600 dark:text-gray-400 dark:border-white/20 dark:hover:border-white'}`}
            >
              {cat}
            </button>
          ))}
        </div>
      </div>

      <div className="flex flex-1 overflow-hidden">

        {/* Left Pane: Dataset List */}
        <div className="w-1/3 border-r border-cream-300 dark:border-nightBorder-600 overflow-y-auto bg-cream-100 dark:bg-black custom-scrollbar transition-colors duration-300">
          {loading ? (
             <div className="p-8 text-center font-mono text-ink-500 dark:text-gray-500 animate-pulse">> INITIALIZING PIPELINE...</div>
          ) : (
            <div className="divide-y divide-cream-300 dark:divide-white/5">
              {filteredResults.map(({ item }) => (
                <CatalogCard 
                  key={item.id}
                  dataset={item}
                  isSelected={selectedDataset?.id === item.id}
                  onClick={() => setSelectedDataset(item)}
                />
              ))}
              {filteredResults.length === 0 && (
                <div className="p-8 text-center text-ink-500 dark:text-gray-600 text-sm">No datasets found matching query.</div>
              )}
            </div>
          )}
        </div>

        {/* Right Pane: Detail & Extraction View */}
        <div className="w-2/3 bg-cream-200 dark:bg-nightBg-800 flex flex-col overflow-hidden relative transition-colors duration-300">
          {/* Background Grid Pattern */}
          <div className="absolute inset-0 bg-[url('https://grainy-gradients.vercel.app/noise.svg')] opacity-5 pointer-events-none"></div>

          {selectedDataset ? (
            <div className="flex flex-col h-full overflow-y-auto custom-scrollbar">
              {/* Dataset Metadata Header */}
              <div className="p-6 border-b border-cream-300 dark:border-white/10 bg-cream-100/50 dark:bg-bloom-card/50">
                <div className="flex justify-between items-start mb-4">
                  <h1 className="text-2xl font-bold text-ink-900 dark:text-white max-w-2xl">{selectedDataset.title}</h1>
                  <div className="flex gap-2">

                    {/* Preview in GIS Viewer */}
                     {selectedDataset.geojsonUrl && onOpenMap && (
                      <button 
                        onClick={() => onOpenMap(selectedDataset)}
                        className="bg-white/50 hover:bg-white text-ink-900 border border-cream-300 dark:bg-white/10 dark:hover:bg-white/20 dark:text-white dark:border-white/10 text-xs font-bold px-4 py-2 rounded transition-colors uppercase tracking-widest"
                      >
                        Preview in GIS Viewer
                      </button>
                    )}

                    {/* Fallback Legacy Button (if no assets array) */}
                    {!selectedDataset.assets && (
                      <button className="bg-brand-green-600 hover:bg-brand-green-500 dark:bg-nightAccent-blue dark:hover:bg-blue-600 text-white text-xs font-bold px-4 py-2 rounded transition-colors uppercase tracking-widest">
                        Download {selectedDataset.format}
                      </button>
                    )}
                  </div>
                </div>

                {/* Assets List */}
                {selectedDataset.assets && selectedDataset.assets.length > 0 && (
                  <div className="mb-6 bg-white/50 dark:bg-black/20 rounded-lg p-4 border border-cream-300 dark:border-white/10">
                    <h3 className="text-xs font-bold text-ink-500 dark:text-gray-400 uppercase tracking-widest mb-3">Available Files & Formats</h3>
                    <div className="grid grid-cols-1 gap-2">
                      {selectedDataset.assets.map((asset) => (
                        <div key={asset.id} className="flex items-center justify-between bg-white dark:bg-white/5 p-2 rounded border border-cream-200 dark:border-white/5">
                           <div className="flex items-center gap-3">
                              <span className={`text-[10px] font-bold px-2 py-0.5 rounded text-white uppercase ${asset.type === 'pdf' ? 'bg-red-500' : asset.type === 'shapefile' ? 'bg-brand-gold-600' : 'bg-brand-green-600'}`}>
                                {asset.type}
                              </span>
                              <span className="text-sm font-medium text-ink-900 dark:text-gray-200">{asset.label}</span>
                           </div>
                           <div className="flex gap-2">
                              {asset.isViewable && (
                                <button 
                                  onClick={() => handleAssetAction(asset, 'view')}
                                  className="text-xs text-ink-700 dark:text-gray-300 hover:text-brand-green-600 dark:hover:text-white font-bold px-2 py-1"
                                >
                                  View
                                </button>
                              )}
                              {asset.isDownloadable && (
                                <button 
                                  onClick={() => handleAssetAction(asset, 'download')}
                                  className="text-xs bg-brand-green-600 hover:bg-brand-green-500 text-white px-3 py-1 rounded font-bold transition-colors"
                                >
                                  Download
                                </button>
                              )}
                           </div>
                        </div>
                      ))}
                    </div>
                  </div>
                )}

                <p className="text-ink-700 dark:text-gray-300 text-sm mb-6 max-w-3xl leading-relaxed">{selectedDataset.description}</p>

                {selectedDataset.tags && (
                  <div className="flex gap-2 mb-6">
                    {selectedDataset.tags.map(tag => (
                      <span key={tag} className="text-[10px] bg-cream-200 dark:bg-white/10 px-2 py-1 rounded text-ink-500 dark:text-gray-400 font-mono">
                        #{tag}
                      </span>
                    ))}
                  </div>
                )}

                <div className="grid grid-cols-4 gap-4 text-xs font-mono border-t border-cream-300 dark:border-white/5 pt-4">
                  <div>
                    <div className="text-ink-500 dark:text-gray-500 mb-1">SOURCE AUTHORITY</div>
                    <div className="text-brand-gold-600 dark:text-nightAccent-gold">{selectedDataset.source}</div>
                  </div>
                  <div>
                    <div className="text-ink-500 dark:text-gray-500 mb-1">LAST UPDATED</div>
                    <div className="text-ink-900 dark:text-white">{selectedDataset.lastUpdated}</div>
                  </div>
                  <div>
                    <div className="text-ink-500 dark:text-gray-500 mb-1">SIZE</div>
                    <div className="text-ink-900 dark:text-white">{selectedDataset.size}</div>
                  </div>
                  <div>
                    <div className="text-ink-500 dark:text-gray-500 mb-1">INTEGRITY HASH</div>
                    <div className="text-ink-700 dark:text-gray-600 truncate">a1b2-c3d4-e5f6</div>
                  </div>
                </div>
              </div>

              {/* Extraction Preview Pane */}
              <div className="flex-1 flex flex-col min-h-[300px]">
                <div className="px-6 py-3 bg-cream-300 dark:bg-black/40 border-b border-cream-300 dark:border-white/10 flex items-center justify-between">
                  <span className="text-xs font-bold text-ink-500 dark:text-gray-400 uppercase tracking-widest">Data Extraction Preview</span>
                  <div className="flex gap-2">
                     <div className="w-2 h-2 rounded-full bg-red-500"></div>
                     <div className="w-2 h-2 rounded-full bg-yellow-500"></div>
                     <div className="w-2 h-2 rounded-full bg-green-500"></div>
                  </div>
                </div>

                <div className="flex-1 overflow-auto p-6 bg-white dark:bg-black">
                  {loadingPreview ? (
                     <div className="h-full flex flex-col items-center justify-center text-ink-500 dark:text-gray-500 font-mono text-xs">
                        <div className="w-8 h-8 border-2 border-brand-green-600 dark:border-bloom-accent border-t-transparent rounded-full animate-spin mb-4"></div>
                        > DECRYPTING STREAM...<br/>
                        > PARSING {selectedDataset.format}...
                     </div>
                  ) : (
                    <div className="font-mono text-xs">
                      {previewData && previewData.length > 0 ? (
                        <table className="w-full text-left border-collapse">
                          <thead>
                            <tr className="border-b border-cream-300 dark:border-white/20 text-brand-green-600 dark:text-nightAccent-gold">
                              {Object.keys(previewData[0]).map(key => (
                                <th key={key} className="py-2 px-4 uppercase">{key}</th>
                              ))}
                            </tr>
                          </thead>
                          <tbody className="divide-y divide-cream-200 dark:divide-white/5 text-ink-700 dark:text-gray-300">
                            {previewData.map((row, idx) => (
                              <tr key={idx} className="hover:bg-cream-100 dark:hover:bg-white/5">
                                {Object.values(row).map((val: any, i) => (
                                  <td key={i} className="py-2 px-4 truncate max-w-xs">{String(val)}</td>
                                ))}
                              </tr>
                            ))}
                          </tbody>
                        </table>
                      ) : (
                        <div className="text-red-500 dark:text-red-400">> ERROR: PREVIEW_UNAVAILABLE</div>
                      )}
                      <div className="mt-4 text-ink-500 dark:text-gray-600 italic">
                        > End of preview. Full dataset contains {selectedDataset.size} of data.
                      </div>
                    </div>
                  )}
                </div>
              </div>
            </div>
          ) : (
            <div className="h-full flex items-center justify-center text-ink-500 dark:text-gray-500 font-mono text-sm">
              > SELECT A DATASET TO INITIALIZE INSPECTOR
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { ViewState, Dataset, MOCK_DATASETS } from './types';
import { Navigation } from './components/Navigation';
import { Hero } from './components/Hero';
import { Features } from './components/Features';
import { Analysis } from './components/Analysis'; // Kept for Home Page widget
import { AnalysisPage } from './components/AnalysisPage'; // New Full Index
import { AnalysisDetailPage } from './components/AnalysisDetailPage'; // New Detail
import { Catalog } from './components/Catalog';
import { Assistant } from './components/Assistant';
import { Footer } from './components/Footer';
import { About } from './components/About';
import { GisViewerPage } from './components/GisViewerPage'; 
import { DevelopersPage } from './components/DevelopersPage';
import InternalLogPage from './components/InternalLogPage';
import { ChangelogPage } from './components/ChangelogPage';
import { SupportPage } from './components/SupportPage';
import { ReportIssuePage } from './components/ReportIssuePage';

// Blog Pages
import BlogIndexPage from './pages/blog/BlogIndexPage';
import BlogPostPage from './pages/blog/BlogPostPage';
import BlogCategoryPage from './pages/blog/BlogCategoryPage';
import BlogArchivePage from './pages/blog/BlogArchivePage';
import BlogSearchPage from './pages/blog/BlogSearchPage';

// Admin Pages
import { AdminAccessPage } from './components/admin/AdminAccessPage';
import { TriagePromptLibraryPage } from './components/admin/TriagePromptLibraryPage';

// Core & Utils
import { getViewFromUrl, getUrlForView, sanitizeRoute, RouteParams } from './utils/routing';
import { MetaManager } from './components/core/MetaManager';
import { safeHistoryAvailable } from './utils/env';

/**
 * THEME GUARDRAIL:
 * Do NOT use raw hex colors (e.g. bg-[#000]) or legacy night-* classes directly.
 * Use semantic tokens: bg-gn-surface dark:bg-gn-surface-dark, text-gn-foreground, etc.
 */

function App() {
  const [initialSanitized] = useState(() => {
    const { view, params } = getViewFromUrl(window.location.search);
    return sanitizeRoute(view, params);
  });

  const [currentView, setCurrentView] = useState<ViewState>(initialSanitized.view);
  const [currentParams, setCurrentParams] = useState<RouteParams>(initialSanitized.params);
  const [showBetaBanner, setShowBetaBanner] = useState(true);

  // Theme State Management
  const [theme, setTheme] = useState<'light' | 'dark'>('light');

  // Load Theme Preference safely
  useEffect(() => {
    try {
      const stored = window.localStorage.getItem('guynode_theme');
      if (stored === 'dark' || stored === 'light') {
        setTheme(stored);
      }
    } catch (e) {
      // Access denied or not available
    }
  }, []);

  // Apply Theme to Root
  useEffect(() => {
    try {
      const root = window.document.documentElement;
      if (theme === 'dark') {
        root.classList.add('dark');
        root.classList.remove('light');
      } else {
        root.classList.remove('dark');
        root.classList.add('light');
      }
      window.localStorage.setItem('guynode_theme', theme);
    } catch (e) {
      // Access denied
    }
  }, [theme]);

  const toggleTheme = () => {
    setTheme(prev => prev === 'light' ? 'dark' : 'light');
  };

  const [redirectNotification, setRedirectNotification] = useState<string | null>(
    initialSanitized.redirected ? "The requested view could not be resolved. Showing safe fallback." : null
  );

  useEffect(() => {
    if (redirectNotification) {
      const timer = setTimeout(() => setRedirectNotification(null), 4000);
      return () => clearTimeout(timer);
    }
  }, [redirectNotification]);

  useEffect(() => {
    if (initialSanitized.redirected && safeHistoryAvailable()) {
       const cleanUrl = getUrlForView(initialSanitized.view, initialSanitized.params);
       window.history.replaceState({}, '', cleanUrl);
    }
  }, [initialSanitized]);

  const [activeMapDataset, setActiveMapDataset] = useState<Dataset | null>(() => {
    if (initialSanitized.view === 'MAP' && initialSanitized.params.datasetId) {
      return MOCK_DATASETS.find(d => d.id === initialSanitized.params.datasetId) || null;
    }
    return null;
  });

  useEffect(() => {
    const handlePopState = () => {
      const { view, params } = getViewFromUrl(window.location.search);
      const { view: safeView, params: safeParams, redirected } = sanitizeRoute(view, params);

      setCurrentView(safeView);
      setCurrentParams(safeParams);

      if (safeView === 'MAP' && safeParams.datasetId) {
        const ds = MOCK_DATASETS.find(d => d.id === safeParams.datasetId);
        setActiveMapDataset(ds || null);
      } else if (safeView === 'MAP' && !safeParams.datasetId) {
        setActiveMapDataset(null);
      }

      if (redirected) {
         setRedirectNotification("The requested URL was invalid. Redirected to safe view.");
         if (safeHistoryAvailable()) {
           window.history.replaceState({}, '', getUrlForView(safeView, safeParams));
         }
      }
    };

    window.addEventListener('popstate', handlePopState);
    return () => window.removeEventListener('popstate', handlePopState);
  }, []);

  const handleNavigation = (view: ViewState, params: RouteParams = {}) => {
    const { view: safeView, params: safeParams } = sanitizeRoute(view, params);

    setCurrentView(safeView);
    setCurrentParams(safeParams);

    if (safeView === 'MAP') {
      if (safeParams.datasetId) {
        const ds = MOCK_DATASETS.find(d => d.id === safeParams.datasetId);
        setActiveMapDataset(ds || null);
      } else {
        setActiveMapDataset(null);
      }
    }

    const url = getUrlForView(safeView, safeParams);
    if (safeHistoryAvailable()) {
      window.history.pushState({}, '', url);
    }
    window.scrollTo(0, 0);
  };

  const navigateToBlog = (view: ViewState, params: any = {}) => {
    handleNavigation(view, params);
  };

  const handleOpenMap = (dataset?: Dataset) => {
    handleNavigation('MAP', dataset ? { datasetId: dataset.id } : {});
  };

  const handleOpenMapById = (datasetId: string) => {
    handleNavigation('MAP', { datasetId });
  };

  const renderContent = () => {
    switch (currentView) {
      case 'HOME':
        return (
          <>
            <Hero setView={(v) => handleNavigation(v)} />
            <Features setView={(v) => handleNavigation(v)} />

            <section className="bg-gn-surface-muted dark:bg-gn-surface-muted-dark py-24 border-y border-gn-border dark:border-gn-border-dark transition-colors duration-300">
              <div className="max-w-7xl mx-auto px-6 grid grid-cols-1 lg:grid-cols-2 gap-16 items-center">
                 <div className="order-2 lg:order-1">
                   <div className="bg-ink-900 border border-ink-900/10 rounded-lg overflow-hidden relative h-[400px]">
                     <img src="https://images.unsplash.com/photo-1583422409516-2895a77efded?q=80&w=800&auto=format&fit=crop" alt="Aerial view of Georgetown, Guyana, showing coastal city blocks and canals" className="w-full h-full object-cover opacity-80 hover:opacity-100 transition-all duration-700" />
                     <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-transparent to-transparent"></div>
                     <div className="absolute bottom-8 left-8">
                       <div className="bg-brand-gold-500 text-ink-900 text-xs font-bold px-2 py-1 mb-2 inline-block">OPEN DATA</div>
                       <h3 className="text-2xl text-white font-bold">Standardized & Ready</h3>
                     </div>
                   </div>
                 </div>
                 <div className="order-1 lg:order-2">
                   <h2 className="text-3xl font-serif font-bold text-gn-foreground dark:text-gn-foreground-dark mb-6">Build on Guyana’s open spatial data.</h2>
                   <p className="text-gn-foreground-muted dark:text-gn-foreground-muted-dark text-lg mb-8 leading-relaxed">
                     Guynode turns scattered public maps into a single, GIS-ready catalog for Guyana. Browse boundaries, settlements, elevation, land use and more in a unified interface that feels at home on desktop or mobile. Preview layers instantly in the GIS viewer, then download clean, standardized files to power your own work in QGIS, ArcGIS, or custom applications.
                   </p>
                   <div className="flex flex-col sm:flex-row gap-4">
                     <button
                       onClick={() => handleNavigation('CATALOG')}
                       className="bg-brand-gold-500 dark:bg-nightAccent-gold hover:bg-brand-gold-600 text-ink-900 dark:text-nightInk-900 font-bold py-3 px-6 rounded transition-colors flex items-center justify-center shadow-sm"
                     >
                       View the Data Catalog →
                     </button>
                     <button
                       onClick={() => handleNavigation('MAP')}
                       className="text-brand-green-600 dark:text-nightAccent-green border border-brand-green-600 dark:border-nightAccent-green hover:bg-brand-green-600 hover:text-white dark:hover:bg-nightAccent-green dark:hover:text-nightInk-50 font-bold py-3 px-6 rounded transition-colors flex items-center justify-center"
                     >
                       Open the GIS Viewer →
                     </button>
                   </div>
                 </div>
              </div>
            </section>

            <Analysis /> {/* Widget for Home Page */}

            <section className="bg-gn-surface dark:bg-gn-surface-dark py-24 text-gn-foreground dark:text-gn-foreground-dark transition-colors duration-300">
              <div className="max-w-7xl mx-auto px-6 grid grid-cols-1 lg:grid-cols-2 gap-12">
                 <div>
                   <h2 className="text-4xl font-serif font-bold mb-6">Request a Demo</h2>
                   <p className="text-gn-foreground-muted dark:text-gn-foreground-muted-dark text-lg mb-8">
                     Help us connect you to the right person. Whether you are a government agency, a private investor, or a researcher, GuyNode has a tailored solution for you.
                   </p>
                 </div>
                 <div className="space-y-4">
                    <div className="grid grid-cols-2 gap-4">
                      <label className="sr-only" htmlFor="firstName">First Name</label>
                      <input id="firstName" type="text" placeholder="First Name" className="border border-gn-border dark:border-gn-border-dark bg-gn-elevated dark:bg-gn-elevated-dark p-3 rounded w-full focus:outline-none focus:border-brand-green-500" />

                      <label className="sr-only" htmlFor="lastName">Last Name</label>
                      <input id="lastName" type="text" placeholder="Last Name" className="border border-gn-border dark:border-gn-border-dark bg-gn-elevated dark:bg-gn-elevated-dark p-3 rounded w-full focus:outline-none focus:border-brand-green-500" />
                    </div>
                    <label className="sr-only" htmlFor="email">Business Email</label>
                    <input id="email" type="email" placeholder="Business Email" className="border border-gn-border dark:border-gn-border-dark bg-gn-elevated dark:bg-gn-elevated-dark p-3 rounded w-full focus:outline-none focus:border-brand-green-500" />

                    <label className="sr-only" htmlFor="industry">Industry</label>
                    <select id="industry" className="border border-gn-border dark:border-gn-border-dark bg-gn-elevated dark:bg-gn-elevated-dark p-3 rounded w-full focus:outline-none focus:border-brand-green-500">
                      <option>Select Industry...</option>
                      <option>Energy</option>
                      <option>Agriculture</option>
                      <option>Mining</option>
                      <option>Government</option>
                    </select>
                    <button className="bg-brand-green-600 hover:bg-brand-green-500 dark:bg-nightAccent-green dark:hover:bg-brand-green-500 text-white font-bold py-4 rounded w-full transition-colors">
                      Submit Request
                    </button>
                    <p className="text-xs text-gn-foreground-muted dark:text-gn-foreground-muted-dark mt-4">
                      By submitting this form, you agree to our Privacy Policy. <br/>
                      Please do not include sensitive personal information.
                    </p>
                 </div>
              </div>
            </section>
          </>
        );
      case 'CATALOG':
        return <Catalog onOpenMap={handleOpenMap} />;
      case 'MAP':
        return (
          <GisViewerPage setView={(v) => handleNavigation(v)} activeDataset={activeMapDataset} />
        );
      case 'DOCS':
        return <DevelopersPage />;

      case 'ANALYSIS':
        // If an ID is present, show detail view, else show index
        if (currentParams.analysisId) {
          return <AnalysisDetailPage analysisId={currentParams.analysisId} navigate={handleNavigation} />;
        }
        return <AnalysisPage navigate={handleNavigation} />;

      case 'ABOUT':
        return <About />;

      case 'SUPPORT':
        return <SupportPage navigate={handleNavigation} section={currentParams.supportSection} />;

      case 'REPORT_ISSUE':
        return <ReportIssuePage navigate={handleNavigation} />;

      case 'INTERNAL_LOG':
        return <InternalLogPage />;
      case 'CHANGELOG':
        return <ChangelogPage />;

      // Blog Module Routes
      case 'BLOG_INDEX':
        return <BlogIndexPage navigate={navigateToBlog} />;
      case 'BLOG_POST':
        return <BlogPostPage navigate={navigateToBlog} params={currentParams} onOpenMap={handleOpenMapById} />;
      case 'BLOG_CATEGORY':
        return <BlogCategoryPage navigate={navigateToBlog} params={currentParams} />;
      case 'BLOG_ARCHIVE':
        return <BlogArchivePage navigate={navigateToBlog} params={currentParams} />;
      case 'BLOG_SEARCH':
        return <BlogSearchPage navigate={navigateToBlog} />;

      // Admin Routes
      // Wired Admin View - passes params to support deep linking to sections
      case 'ADMIN_ACCESS':
        return <AdminAccessPage navigate={(v, p) => handleNavigation(v, p)} params={currentParams} />;
      case 'TRIAGE_PROMPT_LIBRARY':
        return <TriagePromptLibraryPage navigate={(v) => handleNavigation(v)} />;

      default:
        return <div>Page Not Found</div>;
    }
  };

  return (
    <>
      <MetaManager view={currentView} params={currentParams} />
      {/* Skip Link for Accessibility */}
      <a 
        href="#main-content"
        className="sr-only focus:not-sr-only focus:absolute focus:top-4 focus:left-4 z-[100] bg-brand-gold-500 text-black px-4 py-2 rounded font-bold shadow-lg"
      >
        Skip to main content
      </a>

      {showBetaBanner && (
        <div className="bg-gradient-to-r from-brand-green-600 to-brand-green-500 text-white text-xs font-bold py-2 px-6 text-center flex justify-between items-center relative z-[100]">
          <span className="mx-auto">
            🚀 Welcome to the new Guynode Interface (Beta). We are actively migrating datasets.
          </span>
          <button 
            onClick={() => setShowBetaBanner(false)} 
            className="text-white/70 hover:text-white absolute right-4"
            aria-label="Dismiss banner"
          >
            ✕
          </button>
        </div>
      )}

      <div className="min-h-screen bg-gn-surface dark:bg-gn-surface-dark text-gn-foreground dark:text-gn-foreground-dark selection:bg-brand-gold-500 selection:text-ink-900 relative transition-colors duration-300">
        <Navigation 
          currentView={currentView} 
          setView={(v) => handleNavigation(v)} 
          theme={theme}
          toggleTheme={toggleTheme}
        />

        {redirectNotification && (
          <div className="fixed top-20 left-1/2 transform -translate-x-1/2 z-[100] bg-red-900/90 text-white px-6 py-3 rounded-full shadow-2xl border border-red-500/30 flex items-center gap-3 animate-in fade-in slide-in-from-top-4 duration-300">
             <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/></svg>
             <span className="text-sm font-medium">{redirectNotification}</span>
          </div>
        )}

        <main id="main-content">
          {renderContent()}
        </main>
        <Footer setView={(v, p) => handleNavigation(v, p)} />
        <Assistant />
      </div>
    </>
  );
}

export default App;

