import { RouteParams } from '../../utils/routing';

interface AdminConsoleProps {
  navigate: (view: ViewState, params?: RouteParams) => void;
  activeSection?: string;
}

type Tab = 'PROMPTS' | 'HISTORY' | 'DRIFT' | 'DRAFTS' | 'DATASET_UPLOAD' | 'ANALYSIS_DRAFTS' | 'LAUNCH_READINESS' | 'LINKS' | 'CONSISTENCY' | 'GEOJSON' | 'INTEGRITY' | 'UI_REGRESSION' | 'QA_CHECKLIST';

export const AdminConsole: React.FC<AdminConsoleProps> = ({ navigate, activeSection }) => {
  const [activeTab, setActiveTab] = useState<Tab>('PROMPTS');

  // Sync prop section -> internal tab
  useEffect(() => {
    if (activeSection) {
      const mapping: Record<string, Tab> = {
        'prompts': 'PROMPTS',
        'history': 'HISTORY',
        'drift': 'DRIFT',
        'drafts': 'DRAFTS',
        'dataset-upload': 'DATASET_UPLOAD',
        'analysis-drafts': 'ANALYSIS_DRAFTS',
        'launch-readiness': 'LAUNCH_READINESS',
        'link-checker': 'LINKS',
        'consistency': 'CONSISTENCY',
        'geojson': 'GEOJSON',
        'integrity': 'INTEGRITY',
        'ui-regression': 'UI_REGRESSION',
        'qa-checklist': 'QA_CHECKLIST'
      };
      if (mapping[activeSection]) {
        setActiveTab(mapping[activeSection]);
      }
    }
  }, [activeSection]);

  // Sync internal tab click -> URL update
  const handleTabChange = (tab: Tab) => {
    setActiveTab(tab);

    // Reverse Mapping
    const mapping: Record<Tab, string> = {
      'PROMPTS': 'prompts',
      'HISTORY': 'history',
      'DRIFT': 'drift',
      'DRAFTS': 'drafts',
      'DATASET_UPLOAD': 'dataset-upload',
      'ANALYSIS_DRAFTS': 'analysis-drafts',
      'LAUNCH_READINESS': 'launch-readiness',
      'LINKS': 'link-checker',
      'CONSISTENCY': 'consistency',
      'GEOJSON': 'geojson',
      'INTEGRITY': 'integrity',
      'UI_REGRESSION': 'ui-regression',
      'QA_CHECKLIST': 'qa-checklist'
    };

    navigate('ADMIN_ACCESS', { adminSection: mapping[tab] });
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'PROMPTS':
        return (
          <div className="p-8 border border-white/10 rounded-lg bg-white/5">
             <h3 className="text-xl font-bold text-white mb-2">Prompt Library Manager</h3>
             <p className="text-gray-400 text-sm mb-4">
               Centralized access to diagnostic prompt bundles. Use the Triage Library to view and filter bundles.
             </p>
             <button 
               onClick={() => navigate('TRIAGE_PROMPT_LIBRARY')}
               className="bg-bloom-accent hover:bg-blue-600 text-white font-bold py-2 px-4 rounded transition-colors text-sm"
             >
               Launch Triage Library
             </button>
          </div>
        );
      case 'HISTORY': return <div className="p-8 text-gray-500">Global Version History (Placeholder)</div>;
      case 'DRIFT': return <div className="p-8 text-gray-500">Drift Tools (Placeholder)</div>;
      case 'DRAFTS': return <div className="p-8 text-gray-500">Log Drafts (Placeholder)</div>;

      case 'DATASET_UPLOAD': return <DatasetUploadPage />;
      case 'ANALYSIS_DRAFTS': return <AnalysisAdminPage />;
      case 'LAUNCH_READINESS': return <LaunchReadinessPage />;
      case 'LINKS': return <LinkCheckerPanel />;
      case 'CONSISTENCY': return <ConsistencyCheckerPanel />;
      case 'GEOJSON': return <GeojsonValidatorPanel />;
      case 'INTEGRITY': return <InternalIntegrityPanel />;
      case 'UI_REGRESSION': return <UiRegressionPanel />;
      case 'QA_CHECKLIST': return <QAChecklistPanel />;
    }
  };

  return (
    <div className="min-h-screen bg-black text-white pt-20 px-6">
      <div className="max-w-7xl mx-auto">

        {/* Warning Banner */}
        <div className="bg-red-900/30 border border-red-500/30 rounded p-3 mb-8 text-xs text-red-200 flex items-center gap-3">
           <span className="font-bold uppercase tracking-widest bg-red-500/20 px-2 py-0.5 rounded">Developer Tools</span>
           <span>Not secure admin authentication. Do not expose this console on untrusted networks or production environments without gating.</span>
        </div>

        <header className="flex justify-between items-center mb-8 border-b border-white/10 pb-6">
           <div>
             <h1 className="text-3xl font-serif font-bold text-white">System Management & Toolkit</h1>
             <p className="text-gray-400 text-sm mt-1">Guynode Studio • v4.1.0 • Internal Control Plane</p>
           </div>
           <button 
             onClick={() => navigate('ADMIN_ACCESS')}
             className="text-xs text-gray-500 hover:text-white border border-white/10 px-3 py-1 rounded"
           >
             Exit Console
           </button>
        </header>

        <div className="flex flex-col md:flex-row gap-8">
           {/* Sidebar Navigation */}
           <div className="w-full md:w-64 flex-shrink-0">
              <nav className="flex flex-col gap-2">
                 <div className="text-[10px] text-gray-500 font-bold uppercase tracking-wider mb-2 mt-2 px-4 border-b border-white/5 pb-1">Core</div>
                 {(['PROMPTS', 'HISTORY', 'DRIFT', 'DRAFTS'] as Tab[]).map(tab => (
                   <button
                     key={tab}
                     onClick={() => handleTabChange(tab)}
                     className={`text-left px-4 py-2 rounded text-sm font-bold transition-colors ${
                       activeTab === tab 
                         ? 'bg-bloom-accent text-white shadow-lg shadow-blue-900/20' 
                         : 'text-gray-400 hover:bg-white/5 hover:text-white'
                     }`}
                   >
                     {tab === 'PROMPTS' && 'Prompt Library'}
                     {tab === 'HISTORY' && 'Version History'}
                     {tab === 'DRIFT' && 'Drift Tools'}
                     {tab === 'DRAFTS' && 'Log Drafts'}
                   </button>
                 ))}

                 <div className="text-[10px] text-gray-500 font-bold uppercase tracking-wider mb-2 mt-6 px-4 border-b border-white/5 pb-1">Content & Data</div>
                 <button
                     onClick={() => handleTabChange('DATASET_UPLOAD')}
                     className={`text-left px-4 py-2 rounded text-sm font-bold transition-colors ${
                       activeTab === 'DATASET_UPLOAD'
                         ? 'bg-guyana-gold text-black shadow-lg shadow-yellow-500/20' 
                         : 'text-gray-400 hover:bg-white/5 hover:text-white'
                     }`}
                   >
                     Dataset Upload
                 </button>
                 <button
                     onClick={() => handleTabChange('ANALYSIS_DRAFTS')}
                     className={`text-left px-4 py-2 rounded text-sm font-bold transition-colors ${
                       activeTab === 'ANALYSIS_DRAFTS'
                         ? 'bg-purple-600 text-white shadow-lg shadow-purple-500/20' 
                         : 'text-gray-400 hover:bg-white/5 hover:text-white'
                     }`}
                   >
                     Analysis Drafts
                 </button>
                 <button
                     onClick={() => handleTabChange('LAUNCH_READINESS')}
                     className={`text-left px-4 py-2 rounded text-sm font-bold transition-colors ${
                       activeTab === 'LAUNCH_READINESS'
                         ? 'bg-green-600 text-white shadow-lg shadow-green-500/20' 
                         : 'text-gray-400 hover:bg-white/5 hover:text-white'
                     }`}
                   >
                     Launch Readiness
                 </button>

                 <div className="text-[10px] text-gray-500 font-bold uppercase tracking-wider mb-2 mt-6 px-4 border-b border-white/5 pb-1">Reliability</div>
                 {(['LINKS', 'CONSISTENCY', 'GEOJSON', 'INTEGRITY', 'UI_REGRESSION', 'QA_CHECKLIST'] as Tab[]).map(tab => (
                   <button
                     key={tab}
                     onClick={() => handleTabChange(tab)}
                     className={`text-left px-4 py-2 rounded text-sm font-bold transition-colors ${
                       activeTab === tab 
                         ? 'bg-bloom-accent text-white shadow-lg shadow-blue-900/20' 
                         : 'text-gray-400 hover:bg-white/5 hover:text-white'
                     }`}
                   >
                     {tab === 'LINKS' && 'Link Checker'}
                     {tab === 'CONSISTENCY' && 'Consistency'}
                     {tab === 'GEOJSON' && 'GeoJSON Validator'}
                     {tab === 'INTEGRITY' && 'Internal Integrity'}
                     {tab === 'UI_REGRESSION' && 'UI Regression'}
                     {tab === 'QA_CHECKLIST' && 'QA Checklist'}
                   </button>
                 ))}
              </nav>
           </div>

           {/* Main Content Area */}
           <div className="flex-1">
              {renderContent()}
           </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { ViewState } from '../../types';
import { AdminConsole } from './AdminConsole'; 
import { RouteParams } from '../../utils/routing';
import { safeStorageAvailable } from '../../utils/env';

interface AdminAccessPageProps {
  navigate: (view: ViewState, params?: RouteParams) => void;
  params?: RouteParams;
}

const STORAGE_KEY = 'guynode_admin_unlocked';
const ADMIN_PASSWORD = 'guylegend';

export const AdminAccessPage: React.FC<AdminAccessPageProps> = ({ navigate, params }) => {
  const [unlocked, setUnlocked] = useState(false);
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [showConsole, setShowConsole] = useState(false);

  useEffect(() => {
    if (!safeStorageAvailable()) return;

    // 1. Check Session Storage
    const isSessionUnlocked = sessionStorage.getItem(STORAGE_KEY) === 'true';
    if (isSessionUnlocked) {
      setUnlocked(true);
      if (params?.adminSection) {
        setShowConsole(true);
      }
      return;
    }

    // 2. Check URL Override (Dev Helper Only)
    const urlParams = new URLSearchParams(window.location.search);
    if (urlParams.get('adminOverride') === '1') {
      sessionStorage.setItem(STORAGE_KEY, 'true');
      setUnlocked(true);
    }
  }, [params]);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (password === ADMIN_PASSWORD) {
      if (safeStorageAvailable()) {
        sessionStorage.setItem(STORAGE_KEY, 'true');
      }
      setUnlocked(true);
      setError('');
      if (params?.adminSection) {
        setShowConsole(true);
      }
    } else {
      setError('Invalid password.');
    }
  };

  const handleLock = () => {
    if (safeStorageAvailable()) {
      sessionStorage.removeItem(STORAGE_KEY);
    }
    setUnlocked(false);
    setPassword('');
    setShowConsole(false);
  };

  if (!unlocked) {
    return (
      <div className="min-h-screen bg-black flex items-center justify-center px-4 relative overflow-hidden">
        {/* Warning Stripe */}
        <div className="absolute top-0 left-0 w-full bg-yellow-600/20 border-b border-yellow-500/30 p-2 text-center">
           <span className="text-xs font-bold text-yellow-500 tracking-widest uppercase">
             ⚠️ Developer Sandbox Environment - Not Secure for Production Data
           </span>
        </div>

        <div className="w-full max-w-md bg-bloom-card border border-white/10 rounded-lg p-8 shadow-2xl mt-12">
          <div className="text-center mb-6">
            <h1 className="text-2xl font-serif font-bold text-white mb-2">Dev Tools Gateway</h1>
            <p className="text-sm text-gray-400">
              Internal diagnostic and logging tools.<br />
              <span className="text-[10px] uppercase tracking-widest text-guyana-gold font-mono block mt-2">
                (Client-Side Soft Gate Only)
              </span>
            </p>
          </div>

          <form onSubmit={handleLogin} className="space-y-4">
            <div>
              <input 
                type="password" 
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                placeholder="Dev Password"
                className="w-full bg-black/50 border border-white/20 rounded px-4 py-3 text-white focus:outline-none focus:border-bloom-accent text-center"
                autoFocus
              />
            </div>
            {error && <p className="text-red-400 text-xs text-center">{error}</p>}
            <button 
              type="submit"
              className="w-full bg-bloom-accent hover:bg-blue-600 text-white font-bold py-3 rounded transition-colors"
            >
              Unlock Console
            </button>
          </form>

          <div className="mt-6 text-center">
            <button onClick={() => navigate('HOME')} className="text-xs text-gray-500 hover:text-white">
              ← Return to Public Site
            </button>
          </div>
        </div>
      </div>
    );
  }

  if (showConsole) {
    return (
      <div className="relative">
        <div className="bg-red-900/50 text-white text-center text-xs font-bold py-1 border-b border-red-500/30 uppercase tracking-widest">
          Developer Mode • Do NOT enter real user data
        </div>
        <AdminConsole 
          navigate={navigate} 
          activeSection={params?.adminSection} 
        />
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-black text-white pt-20 px-6">
      {/* Banner */}
      <div className="fixed top-16 left-0 w-full bg-stripes-gray z-40 pointer-events-none opacity-5 h-2"></div>

      <div className="max-w-6xl mx-auto">
        <header className="flex justify-between items-center mb-12 border-b border-white/10 pb-6">
          <div>
            <div className="flex items-center gap-3 mb-2">
               <span className="bg-yellow-500/20 text-yellow-500 border border-yellow-500/30 text-[10px] font-bold px-2 py-0.5 rounded">SANDBOX MODE</span>
            </div>
            <h1 className="text-3xl font-serif font-bold text-white">Dev Dashboard</h1>
            <p className="text-gray-400 text-sm mt-1">Guynode Studio Internal Tools</p>
          </div>
          <button 
            onClick={handleLock} 
            className="text-xs font-mono text-gray-500 hover:text-white border border-white/10 px-3 py-1 rounded"
          >
            LOCK SESSION
          </button>
        </header>

        <div className="bg-blue-900/10 border border-blue-500/20 p-4 rounded-lg mb-8 text-sm text-blue-200">
           <strong>Security Note:</strong> This dashboard is a client-side utility for diagnostics (logging, prompt triage, link checking). It does not provide administrative control over the backend or database. Do not use this interface to store sensitive credentials or PII.
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-8 mb-12">

          {/* Card 1: Internal Log */}
          <div className="bg-bloom-card border border-white/10 rounded-lg p-8 hover:border-white/20 transition-colors flex flex-col">
            <div className="w-10 h-10 bg-guyana-gold/20 rounded-full flex items-center justify-center mb-6 text-guyana-gold">
              <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/><polyline points="14 2 14 8 20 8"/><line x1="16" y1="13" x2="8" y2="13"/><line x1="16" y1="17" x2="8" y2="17"/><polyline points="10 9 9 9 8 9"/></svg>
            </div>
            <h2 className="text-xl font-bold text-white mb-3">Internal Log</h2>
            <p className="text-gray-400 text-sm mb-8 flex-grow">
              View internal development log, AI interaction history, and detailed change records.
            </p>
            <button 
              onClick={() => navigate('INTERNAL_LOG')}
              className="w-full bg-white/5 hover:bg-white/10 border border-white/10 text-white font-semibold py-3 rounded transition-colors"
            >
              Open Log
            </button>
          </div>

          {/* Card 2: Triage Prompt Library */}
          <div className="bg-bloom-card border border-white/10 rounded-lg p-8 hover:border-white/20 transition-colors flex flex-col">
            <div className="w-10 h-10 bg-bloom-accent/20 rounded-full flex items-center justify-center mb-6 text-bloom-accent">
               <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m18 15-6-6-6 6"/></svg>
            </div>
            <h2 className="text-xl font-bold text-white mb-3">Prompt Library</h2>
            <p className="text-gray-400 text-sm mb-8 flex-grow">
              Access standard prompt bundles for diagnosing issues, auditing protocols, and guiding development.
            </p>
            <button 
              onClick={() => navigate('TRIAGE_PROMPT_LIBRARY')}
              className="w-full bg-white/5 hover:bg-white/10 border border-white/10 text-white font-semibold py-3 rounded transition-colors"
            >
              Open Library
            </button>
          </div>

          {/* Card 3: System Management & Toolkit */}
          <div className="bg-bloom-card border border-white/10 rounded-lg p-8 hover:border-white/20 transition-colors flex flex-col relative overflow-hidden">
             <div className="absolute top-0 right-0 bg-guyana-gold text-black text-[10px] font-bold px-2 py-1">ACTIVE</div>
            <div className="w-10 h-10 bg-purple-500/20 rounded-full flex items-center justify-center mb-6 text-purple-400">
               <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="3"/><path d="M19.4 15a1.65 1.65 0 0 0 .33 1.82l.06.06a2 2 0 0 1 0 2.83 2 2 0 0 1-2.83 0l-.06-.06a1.65 1.65 0 0 0-1.82-.33 1.65 1.65 0 0 0-1 1.51V21a2 2 0 0 1-2 2 2 2 0 0 1-2-2v-.09A1.65 1.65 0 0 0 9 19.4a1.65 1.65 0 0 0-1.82.33l-.06.06a2 2 0 0 1-2.83 0 2 2 0 0 1 0-2.83l.06.06a1.65 1.65 0 0 0 .33-1.82 1.65 1.65 0 0 0-1.51-1H3a2 2 0 0 1-2-2 2 2 0 0 1 2-2h.09A1.65 1.65 0 0 0 4.6 9a1.65 1.65 0 0 0-.33-1.82l-.06-.06a2 2 0 0 1 0-2.83 2 2 0 0 1 2.83 0l.06.06a1.65 1.65 0 0 0 1.82.33H9a1.65 1.65 0 0 0 1-1.51V3a2 2 0 0 1 2-2 2 2 0 0 1 2 2v.09a1.65 1.65 0 0 0 1 1.51 1.65 1.65 0 0 0 1.82-.33l.06-.06a2 2 0 0 1 2.83 0 2 2 0 0 1 0 2.83l-.06.06a1.65 1.65 0 0 0-.33 1.82V9a1.65 1.65 0 0 0 1.51 1H21a2 2 0 0 1 2 2 2 2 0 0 1-2 2h-.09a1.65 1.65 0 0 0-1.51 1z"/></svg>
            </div>
            <h2 className="text-xl font-bold text-white mb-3">System Toolkit</h2>
            <p className="text-gray-400 text-sm mb-8 flex-grow">
              Launch Readiness, Content Ingestion, and Reliability checks.
            </p>
            <button 
              onClick={() => { setShowConsole(true); navigate('ADMIN_ACCESS', { adminSection: 'prompts' }); }}
              className="w-full bg-purple-500/10 hover:bg-purple-500/20 border border-purple-500/30 text-purple-300 font-semibold py-3 rounded transition-colors"
            >
              Open Toolkit
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

