import React, { useState } from 'react';
import { logEntries } from '../../data/logEntries';

export const VersionHistoryPanel: React.FC = () => {
  const [filter, setFilter] = useState<'ALL' | 'PUBLIC' | 'INTERNAL'>('ALL');

  const sortedLogs = [...logEntries].sort((a, b) => 
    new Date(b.date).getTime() - new Date(a.date).getTime()
  );

  const filteredLogs = sortedLogs.filter(log => {
    if (filter === 'PUBLIC') return log.isPublic;
    if (filter === 'INTERNAL') return !log.isPublic;
    return true;
  });

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-xl font-bold text-white">Version History</h2>
          <p className="text-sm text-gray-400">System changelog and internal development milestones.</p>
        </div>
        <div className="flex gap-2 bg-white/5 p-1 rounded border border-white/10">
          {(['ALL', 'PUBLIC', 'INTERNAL'] as const).map(f => (
            <button
              key={f}
              onClick={() => setFilter(f)}
              className={`px-3 py-1 text-[10px] font-bold rounded transition-colors ${
                filter === f 
                  ? 'bg-bloom-accent text-white' 
                  : 'text-gray-400 hover:text-white hover:bg-white/5'
              }`}
            >
              {f}
            </button>
          ))}
        </div>
      </div>

      <div className="space-y-4">
        {filteredLogs.map(log => (
          <div key={log.id} className="bg-bloom-card border border-white/10 rounded-lg p-4 flex gap-4 hover:border-white/20 transition-colors">
            <div className="flex-shrink-0 w-24">
              <div className="text-xs font-mono text-guyana-gold mb-1">{log.date}</div>
              {log.version && (
                <span className="inline-block bg-white/10 text-white text-[9px] px-1.5 py-0.5 rounded border border-white/5">
                  v{log.version}
                </span>
              )}
            </div>
            <div className="flex-1">
              <h3 className="text-sm font-bold text-white mb-1 flex items-center gap-2">
                {log.title}
                {log.isPublic && <span className="text-[9px] border border-green-500/30 text-green-400 px-1.5 rounded uppercase">Public</span>}
                {!log.isPublic && <span className="text-[9px] border border-yellow-500/30 text-yellow-400 px-1.5 rounded uppercase">Internal</span>}
              </h3>
              <p className="text-xs text-gray-400 leading-relaxed mb-2">{log.summary}</p>

              <div className="flex flex-wrap gap-2 mt-2">
                {log.tags.map(tag => (
                  <span key={tag} className="text-[9px] bg-black/40 text-gray-500 px-2 py-0.5 rounded border border-white/5">
                    #{tag}
                  </span>
                ))}
              </div>
            </div>
          </div>
        ))}
        {filteredLogs.length === 0 && (
          <div className="text-center py-12 border border-white/10 border-dashed rounded text-gray-500 text-sm">
            No logs found for this filter.
          </div>
        )}
      </div>
    </div>
  );
};

import React from 'react';
import { PROMPT_BUNDLES } from '../../data/promptBundles';
import { BUNDLE_VERSION_HISTORY } from '../../data/bundleVersionHistory';
import { summarizeBundleDrift } from '../../utils/protocolDrift';

export const DriftToolsPanel: React.FC = () => {
  // Calculate drift for all bundles
  const driftReports = PROMPT_BUNDLES.map(bundle => 
    summarizeBundleDrift(bundle, BUNDLE_VERSION_HISTORY)
  );

  const drifted = driftReports.filter(r => r.hasDrift);
  const stable = driftReports.filter(r => !r.hasDrift);

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-xl font-bold text-white">Drift Detection</h2>
          <p className="text-sm text-gray-400">Monitor protocol deviations in prompt bundles and versioning.</p>
        </div>
        <div className="flex gap-4 text-xs font-mono">
           <span className="text-red-400 font-bold">{drifted.length} DRIFTING</span>
           <span className="text-green-400 font-bold">{stable.length} STABLE</span>
        </div>
      </div>

      <div className="grid grid-cols-1 gap-4">
        {drifted.length > 0 && (
          <div className="space-y-2">
            <h3 className="text-xs font-bold text-gray-500 uppercase tracking-widest border-b border-white/10 pb-2">Attention Required</h3>
            {drifted.map(report => (
              <div key={report.bundleId} className="bg-red-900/10 border border-red-500/30 rounded p-4">
                <div className="flex justify-between items-start mb-2">
                   <span className="font-bold text-red-200 text-sm font-mono">{report.bundleId}</span>
                   <span className="text-[10px] bg-red-500 text-white px-2 py-0.5 rounded font-bold">DRIFT</span>
                </div>
                <ul className="list-disc pl-4 space-y-1">
                  {report.warnings.map((w, i) => (
                    <li key={i} className="text-xs text-red-300/80">{w}</li>
                  ))}
                </ul>
              </div>
            ))}
          </div>
        )}

        <div className="space-y-2">
          <h3 className="text-xs font-bold text-gray-500 uppercase tracking-widest border-b border-white/10 pb-2">Stable Components</h3>
          <div className="bg-bloom-card border border-white/10 rounded-lg overflow-hidden">
             <table className="w-full text-left text-xs">
               <thead className="bg-white/5 text-gray-400 font-bold">
                 <tr>
                   <th className="p-3">Bundle ID</th>
                   <th className="p-3">Version</th>
                   <th className="p-3 text-right">Status</th>
                 </tr>
               </thead>
               <tbody className="divide-y divide-white/5">
                 {stable.map(report => {
                   const bundle = PROMPT_BUNDLES.find(b => b.id === report.bundleId);
                   return (
                     <tr key={report.bundleId} className="hover:bg-white/5">
                       <td className="p-3 font-mono text-gray-300">{report.bundleId}</td>
                       <td className="p-3 text-gray-500">v{bundle?.version}</td>
                       <td className="p-3 text-right text-green-500 font-bold">OK</td>
                     </tr>
                   );
                 })}
               </tbody>
             </table>
          </div>
        </div>
      </div>
    </div>
  );
};

