type Tab = 'PROMPTS' | 'HISTORY' | 'DRIFT' | 'DRAFTS' | 'DATASET_UPLOAD' | 'ANALYSIS_DRAFTS' | 'LAUNCH_READINESS' | 'LINKS' | 'CONSISTENCY' | 'GEOJSON' | 'INTEGRITY' | 'UI_REGRESSION' | 'QA_CHECKLIST';

export const AdminConsole: React.FC<AdminConsoleProps> = ({ navigate, activeSection }) => {
  const [activeTab, setActiveTab] = useState<Tab>('PROMPTS');

  // Sync prop section -> internal tab
  useEffect(() => {
    if (activeSection) {
      const mapping: Record<string, Tab> = {
        'prompts': 'PROMPTS',
        'history': 'HISTORY',
        'drift': 'DRIFT',
        'drafts': 'DRAFTS',
        'dataset-upload': 'DATASET_UPLOAD',
        'analysis-drafts': 'ANALYSIS_DRAFTS',
        'launch-readiness': 'LAUNCH_READINESS',
        'link-checker': 'LINKS',
        'consistency': 'CONSISTENCY',
        'geojson': 'GEOJSON',
        'integrity': 'INTEGRITY',
        'ui-regression': 'UI_REGRESSION',
        'qa-checklist': 'QA_CHECKLIST'
      };
      if (mapping[activeSection]) {
        setActiveTab(mapping[activeSection]);
      }
    }
  }, [activeSection]);

  // Sync internal tab click -> URL update
  const handleTabChange = (tab: Tab) => {
    setActiveTab(tab);

    // Reverse Mapping
    const mapping: Record<Tab, string> = {
      'PROMPTS': 'prompts',
      'HISTORY': 'history',
      'DRIFT': 'drift',
      'DRAFTS': 'drafts',
      'DATASET_UPLOAD': 'dataset-upload',
      'ANALYSIS_DRAFTS': 'analysis-drafts',
      'LAUNCH_READINESS': 'launch-readiness',
      'LINKS': 'link-checker',
      'CONSISTENCY': 'consistency',
      'GEOJSON': 'geojson',
      'INTEGRITY': 'integrity',
      'UI_REGRESSION': 'ui-regression',
      'QA_CHECKLIST': 'qa-checklist'
    };

    navigate('ADMIN_ACCESS', { adminSection: mapping[tab] });
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'PROMPTS':
        return (
          <div className="p-8 border border-white/10 rounded-lg bg-white/5">
             <h3 className="text-xl font-bold text-white mb-2">Prompt Library Manager</h3>
             <p className="text-gray-400 text-sm mb-4">
               Centralized access to diagnostic prompt bundles. Use the Triage Library to view and filter bundles.
             </p>
             <button 
               onClick={() => navigate('TRIAGE_PROMPT_LIBRARY')}
               className="bg-bloom-accent hover:bg-blue-600 text-white font-bold py-2 px-4 rounded transition-colors text-sm"
             >
               Launch Triage Library
             </button>
          </div>
        );
      case 'HISTORY': return <VersionHistoryPanel />;
      case 'DRIFT': return <DriftToolsPanel />;
      case 'DRAFTS': return <LogDraftsPanel />;

      case 'DATASET_UPLOAD': return <DatasetUploadPage />;
      case 'ANALYSIS_DRAFTS': return <AnalysisAdminPage />;
      case 'LAUNCH_READINESS': return <LaunchReadinessPage navigate={navigate} />;
      case 'LINKS': return <LinkCheckerPanel />;
      case 'CONSISTENCY': return <ConsistencyCheckerPanel />;
      case 'GEOJSON': return <GeojsonValidatorPanel />;
      case 'INTEGRITY': return <InternalIntegrityPanel />;
      case 'UI_REGRESSION': return <UiRegressionPanel />;
      case 'QA_CHECKLIST': return <QAChecklistPanel />;
    }
  };

  return (
    <div className="min-h-screen bg-black text-white pt-20 px-6">
      <div className="max-w-7xl mx-auto">

        {/* Warning Banner */}
        <div className="bg-red-900/30 border border-red-500/30 rounded p-3 mb-8 text-xs text-red-200 flex items-center gap-3">
           <span className="font-bold uppercase tracking-widest bg-red-500/20 px-2 py-0.5 rounded">Developer Tools</span>
           <span>Not secure admin authentication. Do not expose this console on untrusted networks or production environments without gating.</span>
        </div>

        <header className="flex justify-between items-center mb-8 border-b border-white/10 pb-6">
           <div>
             <h1 className="text-3xl font-serif font-bold text-white">System Management & Toolkit</h1>
             <p className="text-gray-400 text-sm mt-1">Guynode Studio • v4.1.0 • Internal Control Plane</p>
           </div>
           <button 
             onClick={() => navigate('ADMIN_ACCESS')}
             className="text-xs text-gray-500 hover:text-white border border-white/10 px-3 py-1 rounded"
           >
             Exit Console
           </button>
        </header>

        <div className="flex flex-col md:flex-row gap-8">
           {/* Sidebar Navigation */}
           <div className="w-full md:w-64 flex-shrink-0">
              <nav className="flex flex-col gap-2">
                 <div className="text-[10px] text-gray-500 font-bold uppercase tracking-wider mb-2 mt-2 px-4 border-b border-white/5 pb-1">Core</div>
                 {(['PROMPTS', 'HISTORY', 'DRIFT', 'DRAFTS'] as Tab[]).map(tab => (
                   <button
                     key={tab}
                     onClick={() => handleTabChange(tab)}
                     className={`text-left px-4 py-2 rounded text-sm font-bold transition-colors ${
                       activeTab === tab 
                         ? 'bg-bloom-accent text-white shadow-lg shadow-blue-900/20' 
                         : 'text-gray-400 hover:bg-white/5 hover:text-white'
                     }`}
                   >
                     {tab === 'PROMPTS' && 'Prompt Library'}
                     {tab === 'HISTORY' && 'Version History'}
                     {tab === 'DRIFT' && 'Drift Tools'}
                     {tab === 'DRAFTS' && 'Log Drafts'}
                   </button>
                 ))}

                 <div className="text-[10px] text-gray-500 font-bold uppercase tracking-wider mb-2 mt-6 px-4 border-b border-white/5 pb-1">Content & Data</div>
                 <button
                     onClick={() => handleTabChange('DATASET_UPLOAD')}
