                         : 'text-gray-400 hover:bg-white/5 hover:text-white'
                     }`}
                   >
                     Dataset Upload
                 </button>
                 <button
                     onClick={() => handleTabChange('ANALYSIS_DRAFTS')}
                     className={`text-left px-4 py-2 rounded text-sm font-bold transition-colors ${
                       activeTab === 'ANALYSIS_DRAFTS'
                         ? 'bg-purple-600 text-white shadow-lg shadow-purple-500/20' 
