                   >
                     Analysis Drafts
                 </button>
                 <button
                     onClick={() => handleTabChange('LAUNCH_READINESS')}
                     className={`text-left px-4 py-2 rounded text-sm font-bold transition-colors ${
                       activeTab === 'LAUNCH_READINESS'
                         ? 'bg-green-600 text-white shadow-lg shadow-green-500/20' 
                         : 'text-gray-400 hover:bg-white/5 hover:text-white'
                     }`}
                   >
                     Launch Readiness
                 </button>

                 <div className="text-[10px] text-gray-500 font-bold uppercase tracking-wider mb-2 mt-6 px-4 border-b border-white/5 pb-1">Reliability</div>
                 {(['LINKS', 'CONSISTENCY', 'GEOJSON', 'INTEGRITY', 'UI_REGRESSION', 'QA_CHECKLIST'] as Tab[]).map(tab => (
                   <button
                     key={tab}
                     onClick={() => handleTabChange(tab)}
                     className={`text-left px-4 py-2 rounded text-sm font-bold transition-colors ${
                       activeTab === tab 
                         ? 'bg-bloom-accent text-white shadow-lg shadow-blue-900/20' 
                         : 'text-gray-400 hover:bg-white/5 hover:text-white'
                     }`}
                   >
                     {tab === 'LINKS' && 'Link Checker'}
                     {tab === 'CONSISTENCY' && 'Consistency'}
                     {tab === 'GEOJSON' && 'GeoJSON Validator'}
                     {tab === 'INTEGRITY' && 'Internal Integrity'}
                     {tab === 'UI_REGRESSION' && 'UI Regression'}
                     {tab === 'QA_CHECKLIST' && 'QA Checklist'}
                   </button>
                 ))}
              </nav>
